#[derive(Debug, Clone, PartialEq)]
pub struct RuntimeEvidenceRunOutput {
    values: Vec<RuntimeEvidenceValue>,
    pub stdout: String,
    pub evidence_stats: RuntimeEvidenceRunStats,
}

impl RuntimeEvidenceRunOutput {
    pub fn roots_text_with_labels(&self, labels: Option<&poly::dump::DumpLabels>) -> String {
        format!(
            "run roots {}\n",
            format_values_with_labels(&self.values, labels)
        )
    }

    pub fn root_value_texts_with_labels(
        &self,
        labels: Option<&poly::dump::DumpLabels>,
    ) -> Vec<String> {
        self.values
            .iter()
            .map(|value| format_value_with_labels(value, labels))
            .collect()
    }

    pub fn roots_text_with_display_context(
        &self,
        labels: Option<&poly::dump::DumpLabels>,
        display: &RuntimeEvidenceDisplayContext,
    ) -> String {
        format!(
            "run roots {}\n",
            format_values_with_display_context(&self.values, labels, display)
        )
    }

    pub fn root_value_texts_with_display_context(
        &self,
        labels: Option<&poly::dump::DumpLabels>,
        display: &RuntimeEvidenceDisplayContext,
    ) -> Vec<String> {
        self.values
            .iter()
            .map(|value| format_value_with_display_context(value, labels, display))
            .collect()
    }
}

#[derive(Debug, Clone, Default, PartialEq, Eq)]
pub struct RuntimeEvidenceDisplayContext {
    constructor_names: HashMap<u32, String>,
}

impl RuntimeEvidenceDisplayContext {
    pub fn new() -> Self {
        Self::default()
    }

    pub fn set_constructor_name(&mut self, def: DefId, name: impl Into<String>) -> &mut Self {
        self.set_constructor_name_id(def.0, name)
    }

    pub fn set_constructor_name_id(&mut self, def: u32, name: impl Into<String>) -> &mut Self {
        self.constructor_names.insert(def, name.into());
        self
    }

    fn constructor_name(&self, def: DefId) -> Option<&str> {
        self.constructor_names.get(&def.0).map(String::as_str)
    }
}

#[derive(Debug, Clone, Default, PartialEq, Eq)]
pub struct RuntimeEvidenceHostConstructors {
    labels_by_def: HashMap<DefId, String>,
    defs_by_label: HashMap<String, DefId>,
    result_ok: Option<DefId>,
    result_err: Option<DefId>,
    file_meta: Option<DefId>,
    file_kind_missing: Option<DefId>,
    file_kind_denied: Option<DefId>,
    file_kind_file: Option<DefId>,
    file_kind_dir: Option<DefId>,
    file_kind_symlink: Option<DefId>,
    file_kind_other: Option<DefId>,
    io_err_not_found: Option<DefId>,
    io_err_denied: Option<DefId>,
    io_err_invalid_path: Option<DefId>,
    io_err_failed: Option<DefId>,
}

impl RuntimeEvidenceHostConstructors {
    pub fn from_labels(labels: &poly::dump::DumpLabels) -> Self {
        let defs_by_label = labels
            .def_labels()
            .map(|(def, label)| (label.to_string(), DefId(def.0)))
            .collect::<HashMap<_, _>>();
        let labels_by_def = defs_by_label
            .iter()
            .map(|(label, def)| (*def, label.clone()))
            .collect::<HashMap<_, _>>();
        Self {
            labels_by_def,
            defs_by_label,
            result_ok: def_with_label(labels, "std.data.result.result.ok"),
            result_err: def_with_label(labels, "std.data.result.result.err"),
            file_meta: def_with_label(labels, "std.io.file.file_meta"),
            file_kind_missing: def_with_label(labels, "std.io.file.file_kind.missing"),
            file_kind_denied: def_with_label(labels, "std.io.file.file_kind.denied"),
            file_kind_file: def_with_label(labels, "std.io.file.file_kind.file"),
            file_kind_dir: def_with_label(labels, "std.io.file.file_kind.dir"),
            file_kind_symlink: def_with_label(labels, "std.io.file.file_kind.symlink"),
            file_kind_other: def_with_label(labels, "std.io.file.file_kind.other"),
            io_err_not_found: def_with_label(labels, "std.io.file.io_err.not_found"),
            io_err_denied: def_with_label(labels, "std.io.file.io_err.denied"),
            io_err_invalid_path: def_with_label(labels, "std.io.file.io_err.invalid_path"),
            io_err_failed: def_with_label(labels, "std.io.file.io_err.failed"),
        }
    }

    fn label_for_def(&self, def: DefId) -> Option<&str> {
        self.labels_by_def.get(&def).map(String::as_str)
    }

    fn def_for_label(&self, label: &str) -> Option<DefId> {
        self.defs_by_label.get(label).copied()
    }
}

fn def_with_label(labels: &poly::dump::DumpLabels, expected: &str) -> Option<DefId> {
    labels
        .def_labels()
        .find_map(|(def, label)| (label == expected).then_some(DefId(def.0)))
}

