fn host_console_out_write(ctx: &mut HostCtx<'_>, payload: &BoundaryValue) -> HostOutcome {
    let text = match boundary_string(payload) {
        Ok(text) => text,
        Err(error) => return HostOutcome::HostError(error),
    };
    let state = match builtin_host_state(ctx) {
        Ok(state) => state,
        Err(error) => return HostOutcome::HostError(error),
    };
    state.push_stdout(&text);
    HostOutcome::Return(BoundaryValue::Unit)
}

fn host_file_load(_: &mut HostCtx<'_>, payload: &BoundaryValue) -> HostOutcome {
    let path = match boundary_path(payload) {
        Ok(path) => path,
        Err(error) => return HostOutcome::HostError(error),
    };
    match fs::read_to_string(&path) {
        Ok(text) => HostOutcome::Return(host_result_ok(BoundaryValue::Str(text))),
        Err(error) => HostOutcome::Return(host_result_err(host_io_error_value(&path, &error))),
    }
}

fn host_file_store(_: &mut HostCtx<'_>, payload: &BoundaryValue) -> HostOutcome {
    let args = match boundary_tuple(payload, 2) {
        Ok(args) => args,
        Err(error) => return HostOutcome::HostError(error),
    };
    let path = match boundary_path(&args[0]) {
        Ok(path) => path,
        Err(error) => return HostOutcome::HostError(error),
    };
    let text = match boundary_string(&args[1]) {
        Ok(text) => text,
        Err(error) => return HostOutcome::HostError(error),
    };
    match fs::write(&path, text) {
        Ok(()) => HostOutcome::Return(host_result_ok(BoundaryValue::Unit)),
        Err(error) => HostOutcome::Return(host_result_err(host_io_error_value(&path, &error))),
    }
}

fn host_file_meta(_: &mut HostCtx<'_>, payload: &BoundaryValue) -> HostOutcome {
    let path = match boundary_path(payload) {
        Ok(path) => path,
        Err(error) => return HostOutcome::HostError(error),
    };
    let (kind, size, readonly, modified) = match fs::symlink_metadata(&path) {
        Ok(meta) => {
            let ty = meta.file_type();
            let kind = if ty.is_file() {
                FILE_KIND_FILE_LABEL
            } else if ty.is_dir() {
                FILE_KIND_DIR_LABEL
            } else if ty.is_symlink() {
                FILE_KIND_SYMLINK_LABEL
            } else {
                FILE_KIND_OTHER_LABEL
            };
            (
                kind,
                meta.len() as i64,
                meta.permissions().readonly(),
                meta.modified()
                    .ok()
                    .and_then(system_time_epoch_nanos)
                    .map(host_instant)
                    .map(host_opt_just)
                    .unwrap_or_else(host_opt_nil),
            )
        }
        Err(error) if error.kind() == io::ErrorKind::NotFound => {
            (FILE_KIND_MISSING_LABEL, 0, false, host_opt_nil())
        }
        Err(error) if error.kind() == io::ErrorKind::PermissionDenied => {
            (FILE_KIND_DENIED_LABEL, 0, false, host_opt_nil())
        }
        Err(_) => (FILE_KIND_OTHER_LABEL, 0, false, host_opt_nil()),
    };
    HostOutcome::Return(BoundaryValue::Constructor {
        ctor: CtorRef::Label(FILE_META_LABEL.to_string()),
        payloads: vec![
            BoundaryValue::Constructor {
                ctor: CtorRef::Label(kind.to_string()),
                payloads: Vec::new(),
            },
            BoundaryValue::Int(size),
            BoundaryValue::Bool(readonly),
            modified,
        ],
    })
}

fn host_clock_now(_: &mut HostCtx<'_>, _: &BoundaryValue) -> HostOutcome {
    let Some(epoch_nanos) = system_time_epoch_nanos(std::time::SystemTime::now()) else {
        return HostOutcome::HostError("clock::now value is outside instant range".to_string());
    };
    HostOutcome::Return(host_instant(epoch_nanos))
}

fn host_native_tcp_listen(ctx: &mut HostCtx<'_>, payload: &BoundaryValue) -> HostOutcome {
    let port = match boundary_tcp_port(payload, "native tcp listen") {
        Ok(port) => port,
        Err(error) => return HostOutcome::HostError(error),
    };
    net_trace(format_args!("listen requested port={port}"));
    let state = match builtin_host_state(ctx) {
        Ok(state) => state,
        Err(error) => return HostOutcome::HostError(error),
    };
    match state.native_tcp_server.listen(port) {
        Ok(listener) => HostOutcome::Return(host_result_ok(listener)),
        Err(error) => HostOutcome::Return(host_result_err(net_err_from_listen_error(port, error))),
    }
}

fn host_native_tcp_port(ctx: &mut HostCtx<'_>, payload: &BoundaryValue) -> HostOutcome {
    let handle = match boundary_host_handle(payload, NATIVE_TCP_LISTENER_TYPE_ID, "native tcp port")
    {
        Ok(handle) => handle,
        Err(error) => return HostOutcome::HostError(error),
    };
    let state = match builtin_host_state(ctx) {
        Ok(state) => state,
        Err(error) => return HostOutcome::HostError(error),
    };
    let Some(port) = state.native_tcp_server.listener_port(handle) else {
        return HostOutcome::HostError(format!(
            "native tcp port expected live listener handle {handle}"
        ));
    };
    net_trace(format_args!("listener port handle={handle} port={port}"));
    HostOutcome::Return(BoundaryValue::Int(i64::from(port)))
}

fn host_native_tcp_accept(ctx: &mut HostCtx<'_>, payload: &BoundaryValue) -> HostOutcome {
    let handle =
        match boundary_host_handle(payload, NATIVE_TCP_LISTENER_TYPE_ID, "native tcp accept") {
            Ok(handle) => handle,
            Err(error) => return HostOutcome::HostError(error),
        };
    net_trace(format_args!("accept requested listener={handle}"));
    let token = match ctx.suspend_multi_shot() {
        Ok(token) => token,
        Err(error) => {
            return HostOutcome::HostError(format!(
                "native tcp accept failed to issue token: {error:?}"
            ));
        }
    };
    let state = match builtin_host_state(ctx) {
        Ok(state) => state,
        Err(error) => return HostOutcome::HostError(error),
    };
    if let Err(error) = state
        .native_tcp_server
        .set_accept_token(handle, token.clone())
    {
        return HostOutcome::HostError(error);
    }
    net_trace(format_args!(
        "accept suspended listener={handle} token={:?}",
        token.id()
    ));
    drop(token);
    HostOutcome::Suspended
}

fn host_native_tcp_respond(ctx: &mut HostCtx<'_>, payload: &BoundaryValue) -> HostOutcome {
    let parts = match boundary_tuple(payload, 2) {
        Ok(parts) => parts,
        Err(error) => return HostOutcome::HostError(error),
    };
    let slot = match boundary_host_handle(
        &parts[0],
        NATIVE_TCP_RESPOND_SLOT_TYPE_ID,
        "native tcp respond",
    ) {
        Ok(slot) => slot,
        Err(error) => return HostOutcome::HostError(error),
    };
    let bytes = match &parts[1] {
        BoundaryValue::Bytes(bytes) => bytes.clone(),
        other => {
            return HostOutcome::HostError(format!(
                "native tcp respond expected bytes response, got {other:?}"
            ));
        }
    };
    net_trace(format_args!(
        "respond requested slot={slot} bytes={}",
        bytes.len()
    ));
    let state = match builtin_host_state(ctx) {
        Ok(state) => state,
        Err(error) => return HostOutcome::HostError(error),
    };
    match state.native_tcp_server.respond(slot, &bytes) {
        NativeTcpRespondResult::Ok => HostOutcome::Return(host_result_ok(BoundaryValue::Unit)),
        NativeTcpRespondResult::Closed => HostOutcome::Return(host_result_err(net_err_closed())),
        NativeTcpRespondResult::Failed(error) => {
            HostOutcome::Return(host_result_err(net_err_failed(error.to_string())))
        }
    }
}

fn host_opt_nil() -> BoundaryValue {
    BoundaryValue::Constructor {
        ctor: CtorRef::Label(OPT_NIL_LABEL.to_string()),
        payloads: Vec::new(),
    }
}

fn host_opt_just(value: BoundaryValue) -> BoundaryValue {
    BoundaryValue::Constructor {
        ctor: CtorRef::Label(OPT_JUST_LABEL.to_string()),
        payloads: vec![value],
    }
}

fn host_instant(epoch_nanos: i64) -> BoundaryValue {
    BoundaryValue::Constructor {
        ctor: CtorRef::Label(INSTANT_LABEL.to_string()),
        payloads: vec![BoundaryValue::Int(epoch_nanos)],
    }
}

fn system_time_epoch_nanos(time: std::time::SystemTime) -> Option<i64> {
    match time.duration_since(std::time::UNIX_EPOCH) {
        Ok(duration) => duration_nanos_i64(duration),
        Err(error) => duration_nanos_i64(error.duration()).and_then(i64::checked_neg),
    }
}

fn duration_nanos_i64(duration: std::time::Duration) -> Option<i64> {
    i64::try_from(duration.as_nanos()).ok()
}

fn host_file_read_at(_: &mut HostCtx<'_>, payload: &BoundaryValue) -> HostOutcome {
    let args = match boundary_tuple(payload, 2) {
        Ok(args) => args,
        Err(error) => return HostOutcome::HostError(error),
    };
    let path = match boundary_path(&args[0]) {
        Ok(path) => path,
        Err(error) => return HostOutcome::HostError(error),
    };
    let range = args[1].clone();
    match fs::read_to_string(&path) {
        Ok(text) => HostOutcome::Return(host_result_ok(BoundaryValue::Tuple(vec![
            BoundaryValue::Str(text),
            range,
        ]))),
        Err(error) => HostOutcome::Return(host_result_err(host_io_error_value(&path, &error))),
    }
}

fn host_file_write_at(_: &mut HostCtx<'_>, payload: &BoundaryValue) -> HostOutcome {
    let args = match boundary_tuple(payload, 3) {
        Ok(args) => args,
        Err(error) => return HostOutcome::HostError(error),
    };
    let path = match boundary_path(&args[0]) {
        Ok(path) => path,
        Err(error) => return HostOutcome::HostError(error),
    };
    let text = match boundary_string(&args[2]) {
        Ok(text) => text,
        Err(error) => return HostOutcome::HostError(error),
    };
    match fs::write(&path, text) {
        Ok(()) => HostOutcome::Return(host_result_ok(BoundaryValue::Unit)),
        Err(error) => HostOutcome::Return(host_result_err(host_io_error_value(&path, &error))),
    }
}

fn host_file_ambient_touch(ctx: &mut HostCtx<'_>, payload: &BoundaryValue) -> HostOutcome {
    let path = match boundary_path(payload) {
        Ok(path) => path,
        Err(error) => return HostOutcome::HostError(error),
    };
    let state = match builtin_host_state(ctx) {
        Ok(state) => state,
        Err(error) => return HostOutcome::HostError(error),
    };
    if state.file_ambient_buffers.contains_key(&path) {
        return HostOutcome::Return(host_result_ok(BoundaryValue::Unit));
    }
    match fs::read_to_string(&path) {
        Ok(text) => {
            state.file_ambient_buffers.insert(path, text);
            HostOutcome::Return(host_result_ok(BoundaryValue::Unit))
        }
        Err(error) => HostOutcome::Return(host_result_err(host_io_error_value(&path, &error))),
    }
}

fn host_file_ambient_get(ctx: &mut HostCtx<'_>, payload: &BoundaryValue) -> HostOutcome {
    let path = match boundary_path(payload) {
        Ok(path) => path,
        Err(error) => return HostOutcome::HostError(error),
    };
    let state = match builtin_host_state(ctx) {
        Ok(state) => state,
        Err(error) => return HostOutcome::HostError(error),
    };
    if let Some(text) = state.file_ambient_buffers.get(&path) {
        return HostOutcome::Return(BoundaryValue::Str(text.clone()));
    }
    match fs::read_to_string(&path) {
        Ok(text) => {
            state.file_ambient_buffers.insert(path, text.clone());
            HostOutcome::Return(BoundaryValue::Str(text))
        }
        Err(error) => {
            host_io_host_error(&["std", "io", "file", "file", "ambient_get"], &path, &error)
        }
    }
}

fn host_file_ambient_set(ctx: &mut HostCtx<'_>, payload: &BoundaryValue) -> HostOutcome {
    let args = match boundary_tuple(payload, 2) {
        Ok(args) => args,
        Err(error) => return HostOutcome::HostError(error),
    };
    let path = match boundary_path(&args[0]) {
        Ok(path) => path,
        Err(error) => return HostOutcome::HostError(error),
    };
    let text = match boundary_string(&args[1]) {
        Ok(text) => text,
        Err(error) => return HostOutcome::HostError(error),
    };
    let state = match builtin_host_state(ctx) {
        Ok(state) => state,
        Err(error) => return HostOutcome::HostError(error),
    };
    if !state.file_ambient_buffers.contains_key(&path)
        && let Err(error) = fs::read_to_string(&path)
    {
        return host_io_host_error(&["std", "io", "file", "file", "ambient_set"], &path, &error);
    }
    state.file_ambient_buffers.insert(path, text);
    HostOutcome::Return(BoundaryValue::Unit)
}

fn host_in_process_server_listen(ctx: &mut HostCtx<'_>, payload: &BoundaryValue) -> HostOutcome {
    let BoundaryValue::Int(port) = payload else {
        return HostOutcome::HostError("in-process server listen expected int port".to_string());
    };
    if *port < 0 {
        return HostOutcome::Return(host_result_err(net_err_failed(format!(
            "invalid port {port}"
        ))));
    }
    let state = match builtin_host_state(ctx) {
        Ok(state) => state,
        Err(error) => return HostOutcome::HostError(error),
    };
    let Some(server) = state.in_process_server.as_mut() else {
        return HostOutcome::HostError("in-process server host is not enabled".to_string());
    };
    HostOutcome::Return(host_result_ok(BoundaryValue::HostHandle {
        type_id: IN_PROCESS_SERVER_LISTENER_TYPE_ID,
        handle: server.listener_handle(*port),
    }))
}

fn host_in_process_server_port(ctx: &mut HostCtx<'_>, payload: &BoundaryValue) -> HostOutcome {
    let handle = match boundary_host_handle(
        payload,
        IN_PROCESS_SERVER_LISTENER_TYPE_ID,
        "in-process server port",
    ) {
        Ok(handle) => handle,
        Err(error) => return HostOutcome::HostError(error),
    };
    let state = match builtin_host_state(ctx) {
        Ok(state) => state,
        Err(error) => return HostOutcome::HostError(error),
    };
    let Some(server) = state.in_process_server.as_mut() else {
        return HostOutcome::HostError("in-process server host is not enabled".to_string());
    };
    let Some(port) = server.listener_port(handle) else {
        return HostOutcome::HostError(format!(
            "in-process server port expected live listener handle {handle}"
        ));
    };
    HostOutcome::Return(BoundaryValue::Int(port))
}

fn host_in_process_server_accept(ctx: &mut HostCtx<'_>, payload: &BoundaryValue) -> HostOutcome {
    match payload {
        BoundaryValue::HostHandle { type_id, .. }
            if *type_id == IN_PROCESS_SERVER_LISTENER_TYPE_ID => {}
        other => {
            return HostOutcome::HostError(format!(
                "in-process server accept expected listener handle, got {other:?}"
            ));
        }
    }
    let token = match ctx.suspend_multi_shot() {
        Ok(token) => token,
        Err(error) => {
            return HostOutcome::HostError(format!(
                "in-process server accept failed to issue token: {error:?}"
            ));
        }
    };
    #[cfg(test)]
    if let Some(state) = ctx.state_mut::<RuntimeBuiltinHostState>() {
        state.test_server_accept_token = Some(token.clone());
    }
    drop(token);
    HostOutcome::Suspended
}

fn host_in_process_server_respond(ctx: &mut HostCtx<'_>, payload: &BoundaryValue) -> HostOutcome {
    let parts = match boundary_tuple(payload, 2) {
        Ok(parts) => parts,
        Err(error) => return HostOutcome::HostError(error),
    };
    let slot = match &parts[0] {
        BoundaryValue::HostHandle { type_id, handle }
            if *type_id == IN_PROCESS_SERVER_RESPOND_SLOT_TYPE_ID =>
        {
            *handle
        }
        other => {
            return HostOutcome::HostError(format!(
                "in-process server respond expected respond slot handle, got {other:?}"
            ));
        }
    };
    let bytes = match &parts[1] {
        BoundaryValue::Bytes(bytes) => bytes.clone(),
        other => {
            return HostOutcome::HostError(format!(
                "in-process server respond expected bytes response, got {other:?}"
            ));
        }
    };
    let state = match builtin_host_state(ctx) {
        Ok(state) => state,
        Err(error) => return HostOutcome::HostError(error),
    };
    let Some(server) = state.in_process_server.as_mut() else {
        return HostOutcome::HostError("in-process server host is not enabled".to_string());
    };
    if !server.responded_slots.insert(slot) {
        return HostOutcome::Return(host_result_err(net_err_closed()));
    }
    let text = String::from_utf8_lossy(&bytes);
    state.push_stdout(&format!("mock-server respond {slot}: {text}\n"));
    HostOutcome::Return(host_result_ok(BoundaryValue::Unit))
}

fn in_process_server_request(slot: u64, payload: Vec<u8>) -> BoundaryValue {
    BoundaryValue::Constructor {
        ctor: CtorRef::Label(IN_PROCESS_SERVER_REQUEST_LABEL.to_string()),
        payloads: vec![BoundaryValue::Record(vec![
            BoundaryField {
                name: "meta".to_string(),
                value: BoundaryValue::HostHandle {
                    type_id: IN_PROCESS_SERVER_REQUEST_META_TYPE_ID,
                    handle: slot,
                },
            },
            BoundaryField {
                name: "payload".to_string(),
                value: BoundaryValue::Bytes(payload),
            },
            BoundaryField {
                name: "slot".to_string(),
                value: BoundaryValue::HostHandle {
                    type_id: IN_PROCESS_SERVER_RESPOND_SLOT_TYPE_ID,
                    handle: slot,
                },
            },
        ])],
    }
}

fn net_err_closed() -> BoundaryValue {
    BoundaryValue::Constructor {
        ctor: CtorRef::Label(NET_ERR_CLOSED_LABEL.to_string()),
        payloads: Vec::new(),
    }
}

fn net_err_already_bound(message: String) -> BoundaryValue {
    BoundaryValue::Constructor {
        ctor: CtorRef::Label("std.io.net.net_err.already_bound".to_string()),
        payloads: vec![BoundaryValue::Str(message)],
    }
}

fn net_err_failed(message: String) -> BoundaryValue {
    BoundaryValue::Constructor {
        ctor: CtorRef::Label("std.io.net.net_err.failed".to_string()),
        payloads: vec![BoundaryValue::Str(message)],
    }
}

fn net_err_from_listen_error(port: u16, error: io::Error) -> BoundaryValue {
    let address = format!("127.0.0.1:{port}");
    if error.kind() == io::ErrorKind::AddrInUse {
        net_err_already_bound(address)
    } else {
        net_err_failed(format!("listen {address}: {error}"))
    }
}

fn builtin_host_state<'a>(
    ctx: &'a mut HostCtx<'_>,
) -> Result<&'a mut RuntimeBuiltinHostState, String> {
    ctx.state_mut::<RuntimeBuiltinHostState>()
        .ok_or_else(|| "host operation state has unexpected type".to_string())
}

fn host_result_ok(value: BoundaryValue) -> BoundaryValue {
    BoundaryValue::Constructor {
        ctor: CtorRef::Label(RESULT_OK_LABEL.to_string()),
        payloads: vec![value],
    }
}

fn host_result_err(value: BoundaryValue) -> BoundaryValue {
    BoundaryValue::Constructor {
        ctor: CtorRef::Label(RESULT_ERR_LABEL.to_string()),
        payloads: vec![value],
    }
}

fn host_io_error_value(path: &PathBuf, error: &io::Error) -> BoundaryValue {
    let path_value = BoundaryValue::Str(runtime_path_text(path));
    let (label, payloads) = match error.kind() {
        io::ErrorKind::NotFound => (IO_ERR_NOT_FOUND_LABEL, vec![path_value]),
        io::ErrorKind::PermissionDenied => (IO_ERR_DENIED_LABEL, vec![path_value]),
        io::ErrorKind::InvalidInput | io::ErrorKind::InvalidData => {
            (IO_ERR_INVALID_PATH_LABEL, vec![path_value])
        }
        _ => (
            IO_ERR_FAILED_LABEL,
            vec![path_value, BoundaryValue::Str(error.to_string())],
        ),
    };
    BoundaryValue::Constructor {
        ctor: CtorRef::Label(label.to_string()),
        payloads,
    }
}

fn host_io_host_error(operation: &[&str], path: &PathBuf, error: &io::Error) -> HostOutcome {
    HostOutcome::HostError(format!(
        "{HOST_IO_ERROR_PREFIX}{}\0{}\0{}",
        operation.join("."),
        runtime_path_text(path),
        host_io_error_kind(error.kind())
    ))
}

fn boundary_string(value: &BoundaryValue) -> Result<String, String> {
    match value {
        BoundaryValue::Str(value) => Ok(value.clone()),
        _ => Err("host operation expected string payload".to_string()),
    }
}

fn boundary_path(value: &BoundaryValue) -> Result<PathBuf, String> {
    boundary_string(value).map(PathBuf::from)
}

fn boundary_host_handle(
    value: &BoundaryValue,
    expected_type_id: u32,
    label: &str,
) -> Result<u64, String> {
    match value {
        BoundaryValue::HostHandle { type_id, handle } if *type_id == expected_type_id => {
            Ok(*handle)
        }
        other => Err(format!(
            "{label} expected host handle type {expected_type_id}, got {other:?}"
        )),
    }
}

fn boundary_tcp_port(value: &BoundaryValue, label: &str) -> Result<u16, String> {
    let BoundaryValue::Int(port) = value else {
        return Err(format!("{label} expected int port"));
    };
    u16::try_from(*port).map_err(|_| format!("{label} port out of range: {port}"))
}

fn boundary_tuple(value: &BoundaryValue, len: usize) -> Result<&[BoundaryValue], String> {
    match value {
        BoundaryValue::Tuple(values) if values.len() == len => Ok(values.as_slice()),
        _ => Err(format!(
            "host operation expected tuple payload of arity {len}"
        )),
    }
}

