// Function-call markers are not an implementation detail of apply/force.
// They are the hygiene boundary that must be closed on every result shape.
#[derive(Debug, Clone, PartialEq, Eq)]
struct EvidenceCallBoundary {
    source: EvidenceMarkerFrameSource,
    markers: Rc<[EvidenceValueMarker]>,
    activate_add_ids: bool,
    handler_path: Option<Vec<String>>,
}

impl EvidenceCallBoundary {
    fn new(
        source: EvidenceMarkerFrameSource,
        markers: Rc<[EvidenceValueMarker]>,
        activate_add_ids: bool,
        handler_path: Option<Vec<String>>,
    ) -> Self {
        Self {
            source,
            markers,
            activate_add_ids,
            handler_path,
        }
    }
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum EvidenceCallBoundaryBypassCert {
    NoActiveMarkerPlan,
    NoFunctionCallMarkers,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum EvidenceContinuationAppendSource {
    Request,
    DirectTail,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum EvidenceContinuationAppendBlocker {
    MarkerFrame,
    ProviderEnv,
    RcShared,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum EvidenceAppendScopeBlockerInfo {
    MarkerFrame { has_handler_path: bool },
    ProviderEnv,
}

impl EvidenceAppendScopeBlockerInfo {
    fn blocker(self) -> EvidenceContinuationAppendBlocker {
        match self {
            Self::MarkerFrame { .. } => EvidenceContinuationAppendBlocker::MarkerFrame,
            Self::ProviderEnv => EvidenceContinuationAppendBlocker::ProviderEnv,
        }
    }
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum EvidenceProviderEnvBoundaryStatus {
    GrantsPermission,
    MissesPermission,
    BlockedByMarkerFrame,
    None,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
struct EvidenceProviderEnvPlacement {
    nearest: EvidenceProviderEnvBoundaryStatus,
    any_after_nearest: EvidenceProviderEnvBoundaryStatus,
    depth: Option<usize>,
    under_then_first: bool,
    under_then_second: bool,
}

impl EvidenceProviderEnvPlacement {
    fn none() -> Self {
        Self {
            nearest: EvidenceProviderEnvBoundaryStatus::None,
            any_after_nearest: EvidenceProviderEnvBoundaryStatus::None,
            depth: None,
            under_then_first: false,
            under_then_second: false,
        }
    }

    fn nearest(
        nearest: EvidenceProviderEnvBoundaryStatus,
        any_after_nearest: EvidenceProviderEnvBoundaryStatus,
        depth: usize,
        under_then_first: bool,
        under_then_second: bool,
    ) -> Self {
        Self {
            nearest,
            any_after_nearest,
            depth: Some(depth),
            under_then_first,
            under_then_second,
        }
    }

    fn has_nearest_boundary(&self) -> bool {
        !matches!(self.nearest, EvidenceProviderEnvBoundaryStatus::None)
    }

    fn merge_any_after_nearest(&mut self, status: EvidenceProviderEnvBoundaryStatus) {
        self.any_after_nearest = merge_provider_env_presence(self.any_after_nearest, status);
    }
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
struct EvidenceProviderEnvLaterGrantPlacement {
    depth: Option<usize>,
    under_then_first: bool,
    under_then_second: bool,
    in_provider_env_next: bool,
}

impl EvidenceProviderEnvLaterGrantPlacement {
    fn none() -> Self {
        Self {
            depth: None,
            under_then_first: false,
            under_then_second: false,
            in_provider_env_next: false,
        }
    }

    fn found(
        depth: usize,
        under_then_first: bool,
        under_then_second: bool,
        in_provider_env_next: bool,
    ) -> Self {
        Self {
            depth: Some(depth),
            under_then_first,
            under_then_second,
            in_provider_env_next,
        }
    }

    fn is_found(self) -> bool {
        self.depth.is_some()
    }
}

#[derive(Debug, Clone, Copy, Default, PartialEq, Eq)]
struct EvidenceContinuationShapeProfile {
    frames: usize,
    then_frames: usize,
    marker_frames: usize,
    provider_env_frames: usize,
    depth_sum: usize,
    max_depth: usize,
}

impl EvidenceContinuationShapeProfile {
    fn prepend_marker_frame(mut self) -> Self {
        if self.frames > 0 {
            self.depth_sum += self.frames;
            self.max_depth += 1;
        }
        self.frames += 1;
        self.marker_frames += 1;
        self
    }

    fn record_frame(&mut self, depth: usize) {
        self.frames += 1;
        self.depth_sum += depth;
        self.max_depth = self.max_depth.max(depth);
    }

    fn record_then(&mut self) {
        self.then_frames += 1;
    }

    fn record_marker_frame(&mut self) {
        self.marker_frames += 1;
    }

    fn record_provider_env(&mut self) {
        self.provider_env_frames += 1;
    }
}

#[derive(Debug, Clone, Copy, Default, PartialEq, Eq)]
struct EvidenceContinuationLiveGauge {
    frames: usize,
    max_depth: usize,
    then_frames: usize,
    state_frames: usize,
    force_frames: usize,
    apply_frames: usize,
    adapter_frames: usize,
    case_frames: usize,
    catch_frames: usize,
    scope_frames: usize,
    marker_frames: usize,
    provider_env_frames: usize,
    aggregate_frames: usize,
    select_frames: usize,
    block_frames: usize,
    ref_set_frames: usize,
}

impl EvidenceContinuationLiveGauge {
    fn record(&mut self, frame: &EvidenceContinuationFrame, depth: usize) {
        self.frames += 1;
        self.max_depth = self.max_depth.max(depth);
        match frame {
            EvidenceContinuationFrame::Then { .. } => {
                self.then_frames += 1;
            }
            EvidenceContinuationFrame::StateFrames { .. } => {
                self.state_frames += 1;
            }
            EvidenceContinuationFrame::ForceThunk { .. }
            | EvidenceContinuationFrame::ForceValueIfThunk { .. } => {
                self.force_frames += 1;
            }
            EvidenceContinuationFrame::ApplyCallee { .. }
            | EvidenceContinuationFrame::ApplyArg { .. }
            | EvidenceContinuationFrame::ApplyForcedCallee { .. } => {
                self.apply_frames += 1;
            }
            EvidenceContinuationFrame::AdaptValue { .. }
            | EvidenceContinuationFrame::WrapThunkValue { .. }
            | EvidenceContinuationFrame::ApplyAdapterArg { .. }
            | EvidenceContinuationFrame::ApplyAdapterResult { .. } => {
                self.adapter_frames += 1;
            }
            EvidenceContinuationFrame::CaseScrutinee { .. } => {
                self.case_frames += 1;
            }
            EvidenceContinuationFrame::CatchBody { .. }
            | EvidenceContinuationFrame::CatchForeignBoundarySegment { .. } => {
                self.catch_frames += 1;
            }
            EvidenceContinuationFrame::ScopePlanForeignCatchBoundary { .. } => {
                self.scope_frames += 1;
            }
            EvidenceContinuationFrame::MarkerFrame { .. } => {
                self.marker_frames += 1;
            }
            EvidenceContinuationFrame::ProviderEnv { .. } => {
                self.provider_env_frames += 1;
            }
            EvidenceContinuationFrame::TupleItems { .. }
            | EvidenceContinuationFrame::RecordSpread { .. }
            | EvidenceContinuationFrame::RecordFields { .. }
            | EvidenceContinuationFrame::PolyVariantPayloads { .. } => {
                self.aggregate_frames += 1;
            }
            EvidenceContinuationFrame::SelectBase { .. } => {
                self.select_frames += 1;
            }
            EvidenceContinuationFrame::BlockStmt { .. } => {
                self.block_frames += 1;
            }
            EvidenceContinuationFrame::RefSetReference { .. }
            | EvidenceContinuationFrame::RefSetForcedReference { .. }
            | EvidenceContinuationFrame::RefSetValue { .. }
            | EvidenceContinuationFrame::RefSetForcedValue { .. }
            | EvidenceContinuationFrame::RefSetResolvedUnit { .. }
            | EvidenceContinuationFrame::RefSetHandleResult { .. }
            | EvidenceContinuationFrame::RefSetHandleValueResult { .. }
            | EvidenceContinuationFrame::RefSetEmitResolvedRequest { .. }
            | EvidenceContinuationFrame::ResolveRefSetValues { .. }
            | EvidenceContinuationFrame::ResolveRefSetFields { .. } => {
                self.ref_set_frames += 1;
            }
        }
    }
}

#[derive(Debug, Clone, Copy, Default, PartialEq, Eq)]
struct EvidenceDirectTailSegmentProfile {
    eval_frames: usize,
    then_frames: usize,
    marker_frames: usize,
    marker_dynamic_frames: usize,
    marker_empty_frames: usize,
    provider_env_frames: usize,
    request_boundaries: usize,
}

#[derive(Debug, Clone, Copy, Default, PartialEq, Eq)]
struct EvidenceResumePlanShadowProfile {
    eval_frames: usize,
    then_frames: usize,
    catch_boundaries: usize,
    catch_same_handler: usize,
    catch_no_routed_handler: usize,
    catch_foreign_handler: usize,
    ref_set_boundaries: usize,
    marker_frames: usize,
    marker_dynamic_frames: usize,
    marker_empty_frames: usize,
    marker_active_add_id_ops: usize,
    marker_handler_boundary_ops: usize,
    provider_env_deltas: usize,
}

impl EvidenceResumePlanShadowProfile {
    fn has_catch_boundary(self) -> bool {
        self.catch_boundaries > 0
    }

    fn has_dynamic_marker(self) -> bool {
        self.marker_dynamic_frames > 0
    }

    fn has_provider_delta(self) -> bool {
        self.provider_env_deltas > 0
    }

    fn is_eval_only(self) -> bool {
        self.catch_boundaries == 0
            && self.ref_set_boundaries == 0
            && self.marker_frames == 0
            && self.provider_env_deltas == 0
    }

    fn request_delta_rejection(self) -> Option<EvidenceResumePlanRequestDeltaReject> {
        if self.catch_boundaries == 0 {
            return Some(EvidenceResumePlanRequestDeltaReject::NoCatchBoundary);
        }
        if self.ref_set_boundaries > 0 {
            return Some(EvidenceResumePlanRequestDeltaReject::RefSetBoundary);
        }
        None
    }
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
struct EvidenceResumePlanPlannedCandidate {
    eval_frames: usize,
    trace: Option<EvidenceResumePlanTraceId>,
    eval_delta: Option<EvidenceEvalDeltaId>,
    boundary_lane: EvidenceScopePlanBoundaryLane,
    request_delta: Option<EvidenceRequestDeltaId>,
    marker_delta: Option<EvidenceMarkerDeltaId>,
    provider_delta: Option<EvidenceProviderDeltaId>,
    route: EvidenceResumePlanRouteCandidate,
    multiplicity: EvidenceResumePlanMultiplicityCandidate,
    estimated_resume_steps: usize,
}

impl EvidenceResumePlanPlannedCandidate {
    fn has_trace(&self) -> bool {
        self.trace.is_some()
    }

    fn has_eval_delta(&self) -> bool {
        self.eval_delta.is_some()
    }

    fn has_request_delta(&self) -> bool {
        self.request_delta.is_some()
    }

    fn has_marker_delta(&self) -> bool {
        self.marker_delta.is_some()
    }

    fn has_provider_delta(&self) -> bool {
        self.provider_delta.is_some()
    }
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum EvidenceResumePlanCandidate {
    Planned(EvidenceResumePlanPlannedCandidate),
    Rejected(EvidenceResumePlanCandidateReject),
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum EvidenceScopePlanBoundaryLane {
    None,
    Catch {
        same_handler: usize,
        no_routed_handler: usize,
        foreign_handler: usize,
    },
    RefSet {
        boundaries: usize,
    },
}

impl EvidenceScopePlanBoundaryLane {
    fn from_shadow_profile(profile: EvidenceResumePlanShadowProfile) -> Self {
        if profile.ref_set_boundaries > 0 {
            return Self::RefSet {
                boundaries: profile.ref_set_boundaries,
            };
        }
        if profile.catch_boundaries == 0 {
            return Self::None;
        }
        Self::Catch {
            same_handler: profile.catch_same_handler,
            no_routed_handler: profile.catch_no_routed_handler,
            foreign_handler: profile.catch_foreign_handler,
        }
    }

    fn has_ref_set(self) -> bool {
        matches!(self, Self::RefSet { boundaries } if boundaries > 0)
    }
}

