#[derive(Debug, Clone, Copy, Default, PartialEq, Eq)]
struct EvidenceResumePlanExecShadowProfile {
    steps: usize,
    eval_steps: usize,
    request_steps: usize,
    marker_steps: usize,
    provider_steps: usize,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum EvidenceResumePlanExecShadowReject {
    MissingTrace,
    MissingEvalDelta,
    MissingRequestDelta,
    MissingMarkerDelta,
    MissingProviderDelta,
    TraceEvalBounds,
    TraceRequestBounds,
    TraceMarkerBounds,
    TraceProviderBounds,
    TraceUnusedPayload,
}

impl EvidenceResumePlanTracePlan {
    fn from_continuation(
        continuation: &EvidenceContinuation,
        routed_yield_handler: Option<ExprId>,
    ) -> Self {
        let mut steps = Vec::new();
        let mut cursor = EvidenceResumePlanTraceCursor::default();
        if let Some(frame) = continuation.frame() {
            frame.append_resume_plan_trace(&mut steps, &mut cursor, routed_yield_handler, true);
        }
        Self {
            steps: Rc::from(steps.into_boxed_slice()),
        }
    }

    fn step_count(&self) -> usize {
        self.steps.len()
    }

    fn eval_count(&self) -> usize {
        self.steps
            .iter()
            .filter(|step| matches!(step, EvidenceResumePlanStep::Eval(_)))
            .count()
    }

    fn request_count(&self) -> usize {
        self.steps
            .iter()
            .filter(|step| matches!(step, EvidenceResumePlanStep::Request(_)))
            .count()
    }

    fn marker_count(&self) -> usize {
        self.steps
            .iter()
            .filter(|step| matches!(step, EvidenceResumePlanStep::Marker(_)))
            .count()
    }

    fn provider_count(&self) -> usize {
        self.steps
            .iter()
            .filter(|step| matches!(step, EvidenceResumePlanStep::Provider(_)))
            .count()
    }

    fn exec_shadow_profile(
        &self,
        eval_delta: &EvidenceEvalDeltaPlan,
        request_delta: &EvidenceRequestDeltaPlan,
        marker_delta: &EvidenceMarkerDeltaPlan,
        provider_delta: &EvidenceProviderDeltaPlan,
    ) -> Result<EvidenceResumePlanExecShadowProfile, EvidenceResumePlanExecShadowReject> {
        let mut profile = EvidenceResumePlanExecShadowProfile::default();
        let mut cursor = EvidenceResumePlanTraceCursor::default();
        for step in self.steps.iter().copied() {
            profile.steps += 1;
            match step {
                EvidenceResumePlanStep::Eval(index) => {
                    if index != cursor.eval || index >= eval_delta.frame_count() {
                        return Err(EvidenceResumePlanExecShadowReject::TraceEvalBounds);
                    }
                    cursor.eval += 1;
                    profile.eval_steps += 1;
                }
                EvidenceResumePlanStep::Request(index) => {
                    if index != cursor.request || index >= request_delta.frame_count() {
                        return Err(EvidenceResumePlanExecShadowReject::TraceRequestBounds);
                    }
                    cursor.request += 1;
                    profile.request_steps += 1;
                }
                EvidenceResumePlanStep::Marker(index) => {
                    if index != cursor.marker || index >= marker_delta.frame_count() {
                        return Err(EvidenceResumePlanExecShadowReject::TraceMarkerBounds);
                    }
                    cursor.marker += 1;
                    profile.marker_steps += 1;
                }
                EvidenceResumePlanStep::Provider(index) => {
                    if index != cursor.provider || index >= provider_delta.frame_count() {
                        return Err(EvidenceResumePlanExecShadowReject::TraceProviderBounds);
                    }
                    cursor.provider += 1;
                    profile.provider_steps += 1;
                }
            }
        }

        if cursor.eval != eval_delta.frame_count()
            || cursor.request != request_delta.frame_count()
            || cursor.marker != marker_delta.frame_count()
            || cursor.provider != provider_delta.frame_count()
        {
            return Err(EvidenceResumePlanExecShadowReject::TraceUnusedPayload);
        }

        Ok(profile)
    }
}

impl EvidenceResumeScopedTracePlan {
    fn from_continuation(
        continuation: &EvidenceContinuation,
        routed_yield_handler: Option<ExprId>,
    ) -> Self {
        let mut builder = EvidenceResumeScopedTraceBuilder::new();
        if let Some(frame) = continuation.frame() {
            builder.append_frame(0, frame, routed_yield_handler);
        }
        builder.finish()
    }

    fn scope_count(&self) -> usize {
        self.scopes.len()
    }

    fn provider_child_scope_count(&self) -> usize {
        self.scope_count().saturating_sub(1)
    }

    fn step_count(&self) -> usize {
        self.scopes.iter().map(|scope| scope.steps.len()).sum()
    }

    fn eval_count(&self) -> usize {
        self.scopes
            .iter()
            .map(EvidenceResumeScopeTracePlan::eval_count)
            .sum()
    }

    fn request_count(&self) -> usize {
        self.scopes
            .iter()
            .map(EvidenceResumeScopeTracePlan::request_count)
            .sum()
    }

    fn marker_count(&self) -> usize {
        self.scopes
            .iter()
            .map(EvidenceResumeScopeTracePlan::marker_count)
            .sum()
    }

    fn root_marker_count(&self) -> usize {
        self.scopes
            .first()
            .map(EvidenceResumeScopeTracePlan::marker_count)
            .unwrap_or(0)
    }

    fn child_marker_count(&self) -> usize {
        self.scopes
            .iter()
            .skip(1)
            .map(EvidenceResumeScopeTracePlan::marker_count)
            .sum()
    }

    fn scope_plan_shadow(
        &self,
        marker_delta_frames: usize,
        weighted_resume_steps: usize,
    ) -> EvidenceScopePlanShadow {
        let root_marker_match = self.root_marker_count() == marker_delta_frames;
        let profile = EvidenceScopePlanShadowProfile {
            weighted_resume_steps,
            scope_count: self.scope_count(),
            provider_child_scopes: self.provider_child_scope_count(),
            eval_steps: self.eval_count(),
            request_steps: self.request_count(),
            marker_steps: self.marker_count(),
            child_marker_steps: self.child_marker_count(),
            root_marker_match,
        };
        if root_marker_match {
            EvidenceScopePlanShadow::Planned(profile)
        } else {
            EvidenceScopePlanShadow::Rejected(EvidenceScopePlanShadowReject::RootMarkerMismatch)
        }
    }

    fn sidecar_plan_shadow(
        &self,
        input: EvidenceSidecarPlanShadowInput,
    ) -> EvidenceSidecarPlanShadow {
        if self.root_marker_count() != input.marker_frames {
            return EvidenceSidecarPlanShadow::Rejected(
                EvidenceSidecarPlanShadowReject::RootMarkerMismatch,
            );
        }
        if self.provider_child_scope_count() != input.provider_frames {
            return EvidenceSidecarPlanShadow::Rejected(
                EvidenceSidecarPlanShadowReject::ProviderScopeMismatch,
            );
        }
        EvidenceSidecarPlanShadow::Planned(EvidenceSidecarPlanShadowProfile {
            marker_frames: input.marker_frames,
            marker_active_add_id_ops: input.marker_active_add_id_ops,
            marker_handler_boundary_ops: input.marker_handler_boundary_ops,
            provider_frames: input.provider_frames,
            provider_slots: input.provider_slots,
            provider_handler_candidates: input.provider_handler_candidates,
            child_marker_frames: self.child_marker_count(),
            legacy_frame_avoid_estimate: input.marker_frames + input.provider_frames,
        })
    }
}

impl EvidenceResumeScopeTracePlan {
    fn eval_count(&self) -> usize {
        self.steps
            .iter()
            .filter(|step| matches!(step, EvidenceResumeScopeStep::Eval(_)))
            .count()
    }

    fn request_count(&self) -> usize {
        self.steps
            .iter()
            .filter(|step| matches!(step, EvidenceResumeScopeStep::Request(_)))
            .count()
    }

    fn marker_count(&self) -> usize {
        self.steps
            .iter()
            .filter(|step| matches!(step, EvidenceResumeScopeStep::Marker(_)))
            .count()
    }
}

impl EvidenceResumeScopedTraceBuilder {
    fn new() -> Self {
        let mut builder = Self::default();
        builder.push_scope();
        builder
    }

    fn push_scope(&mut self) -> usize {
        let scope = self.scopes.len();
        self.scopes.push(Vec::new());
        self.cursors.push(EvidenceResumePlanTraceCursor::default());
        scope
    }

    fn finish(self) -> EvidenceResumeScopedTracePlan {
        EvidenceResumeScopedTracePlan {
            scopes: self
                .scopes
                .into_iter()
                .map(|steps| EvidenceResumeScopeTracePlan {
                    steps: Rc::from(steps.into_boxed_slice()),
                })
                .collect::<Vec<_>>()
                .into(),
        }
    }

    fn push_step(&mut self, scope: usize, step: EvidenceResumeScopeStep) {
        self.scopes[scope].push(step);
    }

    fn append_frame(
        &mut self,
        scope: usize,
        frame: &EvidenceContinuationFrame,
        routed_yield_handler: Option<ExprId>,
    ) {
        match frame {
            EvidenceContinuationFrame::Then { first, second } => {
                if let Some(frame) = first.frame() {
                    self.append_frame(scope, frame, routed_yield_handler);
                }
                if let Some(frame) = second.frame() {
                    self.append_frame(scope, frame, routed_yield_handler);
                }
            }
            EvidenceContinuationFrame::StateFrames { inner, .. } => {
                if let Some(frame) = inner.frame() {
                    self.append_frame(scope, frame, routed_yield_handler);
                }
            }
            EvidenceContinuationFrame::CatchBody { next, .. } => {
                let index = self.cursors[scope].request;
                self.cursors[scope].request += 1;
                self.push_step(scope, EvidenceResumeScopeStep::Request(index));
                if let Some(frame) = next.frame() {
                    self.append_frame(scope, frame, routed_yield_handler);
                }
            }
            EvidenceContinuationFrame::CatchForeignBoundarySegment { boundaries, next } => {
                for _ in boundaries.iter() {
                    let index = self.cursors[scope].request;
                    self.cursors[scope].request += 1;
                    self.push_step(scope, EvidenceResumeScopeStep::Request(index));
                }
                if let Some(frame) = next.frame() {
                    self.append_frame(scope, frame, routed_yield_handler);
                }
            }
            EvidenceContinuationFrame::ScopePlanForeignCatchBoundary {
                scope: scope_continuation,
                boundaries,
                next,
                ..
            } => {
                if let Some(frame) = scope_continuation.frame() {
                    self.append_frame(scope, frame, routed_yield_handler);
                }
                for _ in boundaries.iter() {
                    let index = self.cursors[scope].request;
                    self.cursors[scope].request += 1;
                    self.push_step(scope, EvidenceResumeScopeStep::Request(index));
                }
                if let Some(frame) = next.frame() {
                    self.append_frame(scope, frame, routed_yield_handler);
                }
            }
            EvidenceContinuationFrame::MarkerFrame { next, .. } => {
                let index = self.cursors[scope].marker;
                self.cursors[scope].marker += 1;
                self.push_step(scope, EvidenceResumeScopeStep::Marker(index));
                if let Some(frame) = next.frame() {
                    self.append_frame(scope, frame, routed_yield_handler);
                }
            }
            EvidenceContinuationFrame::ProviderEnv { next, .. } => {
                let provider = self.cursors[scope].provider;
                self.cursors[scope].provider += 1;
                let child_scope = self.push_scope();
                self.push_step(
                    scope,
                    EvidenceResumeScopeStep::Provider {
                        provider,
                        child_scope,
                    },
                );
                if let Some(frame) = next.frame() {
                    self.append_frame(child_scope, frame, routed_yield_handler);
                }
            }
            EvidenceContinuationFrame::RefSetHandleResult { .. }
            | EvidenceContinuationFrame::RefSetHandleValueResult { .. } => {}
            _ => {
                let index = self.cursors[scope].eval;
                self.cursors[scope].eval += 1;
                self.push_step(scope, EvidenceResumeScopeStep::Eval(index));
                if let Some(next) = frame.tail_ref()
                    && let Some(frame) = next.frame()
                {
                    self.append_frame(scope, frame, routed_yield_handler);
                }
            }
        }
    }
}

#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
struct EvidenceEvalDeltaId(usize);

#[derive(Debug, Clone, PartialEq)]
struct EvidenceEvalDeltaPlan {
    frames: Rc<[EvidenceEvalDeltaFramePlan]>,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum EvidenceEvalDeltaFrameKind {
    Force,
    Apply,
    Adapter,
    Case,
    Aggregate,
    Select,
    Block,
    RefSet,
}

#[derive(Debug, Clone, PartialEq)]
enum EvidenceEvalDeltaFramePlan {
    ForceThunk {
        target_value_is_thunk: bool,
    },
    ForceValueIfThunk,
    ApplyCallee {
        site: Option<ExprId>,
        arg: ExprId,
        env: Env,
    },
    ApplyArg {
        site: Option<ExprId>,
        callee: SharedValue,
    },
    ApplyForcedCallee {
        site: Option<ExprId>,
        arg: SharedValue,
    },
    AdaptValue {
        source: Type,
        target: Type,
    },
    WrapThunkValue,
    ApplyAdapterArg {
        function: SharedValue,
        ret_markers: Vec<EvidenceValueMarker>,
        source_ret: Type,
        target_ret: Type,
    },
    ApplyAdapterResult {
        ret_markers: Vec<EvidenceValueMarker>,
        source_ret: Type,
        target_ret: Type,
    },
    CaseScrutinee {
        arms: Rc<[control_ir::CaseArm]>,
        env: Env,
    },
    TupleItems {
        values: Vec<SharedValue>,
        rest: Rc<[ExprId]>,
        env: Env,
    },
    RecordSpread {
        fields: Rc<[control_ir::RecordField]>,
        env: Env,
    },
    RecordFields {
        values: Vec<RuntimeEvidenceValueField>,
        rest: Rc<[control_ir::RecordField]>,
        env: Env,
    },
    PolyVariantPayloads {
        tag: String,
        values: Vec<SharedValue>,
        rest: Rc<[ExprId]>,
        env: Env,
    },
    SelectBase {
        name: String,
        resolution: Option<SelectResolution>,
    },
    BlockStmt {
        resume: EvidenceBlockResume,
        rest: Rc<[Stmt]>,
        tail: Option<ExprId>,
        env: Env,
        last: SharedValue,
    },
    RefSetReference {
        value: ExprId,
        env: Env,
    },
    RefSetForcedReference {
        value: ExprId,
        env: Env,
    },
    RefSetValue {
        reference: SharedValue,
    },
    RefSetForcedValue {
        reference: SharedValue,
    },
    RefSetResolvedUnit,
    RefSetEmitResolvedRequest {
        request: EvidenceRequest,
        assigned: SharedValue,
        mode: EvidenceRefSetResumeMode,
    },
    ResolveRefSetValues {
        values: Vec<SharedValue>,
        assigned: SharedValue,
        out: Vec<SharedValue>,
        index: usize,
        finish: EvidenceRefSetFinish,
    },
    ResolveRefSetFields {
        fields: Vec<RuntimeEvidenceValueField>,
        assigned: SharedValue,
        out: Vec<RuntimeEvidenceValueField>,
        index: usize,
    },
}

impl EvidenceEvalDeltaFramePlan {
    fn kind(&self) -> EvidenceEvalDeltaFrameKind {
        match self {
            Self::ForceThunk { .. } | Self::ForceValueIfThunk => EvidenceEvalDeltaFrameKind::Force,
            Self::ApplyCallee { .. } | Self::ApplyArg { .. } | Self::ApplyForcedCallee { .. } => {
                EvidenceEvalDeltaFrameKind::Apply
            }
            Self::AdaptValue { .. }
            | Self::WrapThunkValue
            | Self::ApplyAdapterArg { .. }
            | Self::ApplyAdapterResult { .. } => EvidenceEvalDeltaFrameKind::Adapter,
            Self::CaseScrutinee { .. } => EvidenceEvalDeltaFrameKind::Case,
            Self::TupleItems { .. }
            | Self::RecordSpread { .. }
            | Self::RecordFields { .. }
            | Self::PolyVariantPayloads { .. } => EvidenceEvalDeltaFrameKind::Aggregate,
            Self::SelectBase { .. } => EvidenceEvalDeltaFrameKind::Select,
            Self::BlockStmt { .. } => EvidenceEvalDeltaFrameKind::Block,
            Self::RefSetReference { .. }
            | Self::RefSetForcedReference { .. }
            | Self::RefSetValue { .. }
            | Self::RefSetForcedValue { .. }
            | Self::RefSetResolvedUnit
            | Self::RefSetEmitResolvedRequest { .. }
            | Self::ResolveRefSetValues { .. }
            | Self::ResolveRefSetFields { .. } => EvidenceEvalDeltaFrameKind::RefSet,
        }
    }

    fn from_continuation_frame(frame: &EvidenceContinuationFrame) -> Option<Self> {
        match frame {
            EvidenceContinuationFrame::ForceThunk {
                target_value_is_thunk,
                ..
            } => Some(Self::ForceThunk {
                target_value_is_thunk: *target_value_is_thunk,
            }),
            EvidenceContinuationFrame::ForceValueIfThunk { .. } => Some(Self::ForceValueIfThunk),
            EvidenceContinuationFrame::ApplyCallee { site, arg, env, .. } => {
                Some(Self::ApplyCallee {
                    site: *site,
                    arg: *arg,
                    env: env.clone(),
                })
            }
            EvidenceContinuationFrame::ApplyArg { site, callee, .. } => Some(Self::ApplyArg {
                site: *site,
                callee: callee.clone(),
            }),
            EvidenceContinuationFrame::ApplyForcedCallee { site, arg, .. } => {
                Some(Self::ApplyForcedCallee {
                    site: *site,
                    arg: arg.clone(),
                })
            }
            EvidenceContinuationFrame::AdaptValue { source, target, .. } => {
                Some(Self::AdaptValue {
                    source: source.clone(),
                    target: target.clone(),
                })
            }
            EvidenceContinuationFrame::WrapThunkValue { .. } => Some(Self::WrapThunkValue),
            EvidenceContinuationFrame::ApplyAdapterArg {
                function,
                ret_markers,
                source_ret,
                target_ret,
                ..
            } => Some(Self::ApplyAdapterArg {
                function: function.clone(),
                ret_markers: ret_markers.clone(),
                source_ret: source_ret.clone(),
                target_ret: target_ret.clone(),
            }),
            EvidenceContinuationFrame::ApplyAdapterResult {
                ret_markers,
                source_ret,
                target_ret,
                ..
            } => Some(Self::ApplyAdapterResult {
                ret_markers: ret_markers.clone(),
                source_ret: source_ret.clone(),
                target_ret: target_ret.clone(),
            }),
            EvidenceContinuationFrame::CaseScrutinee { arms, env, .. } => {
                Some(Self::CaseScrutinee {
                    arms: arms.clone(),
                    env: env.clone(),
                })
            }
            EvidenceContinuationFrame::TupleItems {
                values, rest, env, ..
            } => Some(Self::TupleItems {
                values: values.clone(),
                rest: rest.clone(),
                env: env.clone(),
            }),
            EvidenceContinuationFrame::RecordSpread { fields, env, .. } => {
                Some(Self::RecordSpread {
                    fields: fields.clone(),
                    env: env.clone(),
                })
            }
            EvidenceContinuationFrame::RecordFields {
                values, rest, env, ..
            } => Some(Self::RecordFields {
                values: values.clone(),
                rest: rest.clone(),
                env: env.clone(),
            }),
            EvidenceContinuationFrame::PolyVariantPayloads {
                tag,
                values,
                rest,
                env,
                ..
            } => Some(Self::PolyVariantPayloads {
                tag: tag.clone(),
                values: values.clone(),
                rest: rest.clone(),
                env: env.clone(),
            }),
            EvidenceContinuationFrame::SelectBase {
                name, resolution, ..
            } => Some(Self::SelectBase {
                name: name.clone(),
                resolution: resolution.clone(),
            }),
            EvidenceContinuationFrame::BlockStmt {
                resume,
                rest,
                tail,
                env,
                last,
                ..
            } => Some(Self::BlockStmt {
                resume: resume.clone(),
                rest: rest.clone(),
                tail: *tail,
                env: env.clone(),
                last: last.clone(),
            }),
            EvidenceContinuationFrame::RefSetReference { value, env, .. } => {
                Some(Self::RefSetReference {
                    value: *value,
                    env: env.clone(),
                })
            }
            EvidenceContinuationFrame::RefSetForcedReference { value, env, .. } => {
                Some(Self::RefSetForcedReference {
                    value: *value,
                    env: env.clone(),
                })
            }
            EvidenceContinuationFrame::RefSetValue { reference, .. } => Some(Self::RefSetValue {
                reference: reference.clone(),
            }),
            EvidenceContinuationFrame::RefSetForcedValue { reference, .. } => {
                Some(Self::RefSetForcedValue {
                    reference: reference.clone(),
                })
            }
            EvidenceContinuationFrame::RefSetResolvedUnit { .. } => Some(Self::RefSetResolvedUnit),
            EvidenceContinuationFrame::RefSetEmitResolvedRequest {
                request,
                assigned,
                mode,
                ..
            } => Some(Self::RefSetEmitResolvedRequest {
                request: request.clone(),
                assigned: assigned.clone(),
                mode: *mode,
            }),
            EvidenceContinuationFrame::ResolveRefSetValues {
                values,
                assigned,
                out,
                index,
                finish,
                ..
            } => Some(Self::ResolveRefSetValues {
                values: values.clone(),
                assigned: assigned.clone(),
                out: out.clone(),
                index: *index,
                finish: finish.clone(),
            }),
            EvidenceContinuationFrame::ResolveRefSetFields {
                fields,
                assigned,
                out,
                index,
                ..
            } => Some(Self::ResolveRefSetFields {
                fields: fields.clone(),
                assigned: assigned.clone(),
                out: out.clone(),
                index: *index,
            }),
            _ => None,
        }
    }

    fn to_continuation(&self, next: EvidenceContinuation) -> EvidenceContinuation {
        match self {
            Self::ForceThunk {
                target_value_is_thunk,
            } => EvidenceContinuation::force_thunk(*target_value_is_thunk, next),
            Self::ForceValueIfThunk => EvidenceContinuation::force_value_if_thunk(next),
            Self::ApplyCallee { site, arg, env } => {
                EvidenceContinuation::apply_callee(*site, *arg, env.clone(), next)
            }
            Self::ApplyArg { site, callee } => {
                EvidenceContinuation::apply_arg(*site, callee.clone(), next)
            }
            Self::ApplyForcedCallee { site, arg } => {
                EvidenceContinuation::apply_forced_callee(*site, arg.clone(), next)
            }
            Self::AdaptValue { source, target } => {
                EvidenceContinuation::adapt_value(source.clone(), target.clone(), next)
            }
            Self::WrapThunkValue => EvidenceContinuation::wrap_thunk_value(next),
            Self::ApplyAdapterArg {
                function,
                ret_markers,
                source_ret,
                target_ret,
            } => EvidenceContinuation::apply_adapter_arg(
                function.clone(),
                ret_markers.clone(),
                source_ret.clone(),
                target_ret.clone(),
                next,
            ),
            Self::ApplyAdapterResult {
                ret_markers,
                source_ret,
                target_ret,
            } => EvidenceContinuation::apply_adapter_result(
                ret_markers.clone(),
                source_ret.clone(),
                target_ret.clone(),
                next,
            ),
            Self::CaseScrutinee { arms, env } => {
                EvidenceContinuation::case_scrutinee(arms.clone(), env.clone(), next)
            }
            Self::TupleItems { values, rest, env } => {
                EvidenceContinuation::tuple_items(values.clone(), rest.clone(), env.clone(), next)
            }
            Self::RecordSpread { fields, env } => {
                EvidenceContinuation::record_spread(fields.clone(), env.clone(), next)
            }
            Self::RecordFields { values, rest, env } => {
                EvidenceContinuation::record_fields(values.clone(), rest.clone(), env.clone(), next)
            }
            Self::PolyVariantPayloads {
                tag,
                values,
                rest,
                env,
            } => EvidenceContinuation::poly_variant_payloads(
                tag.clone(),
                values.clone(),
                rest.clone(),
                env.clone(),
                next,
            ),
            Self::SelectBase { name, resolution } => {
                EvidenceContinuation::select_base(name.clone(), resolution.clone(), next)
            }
            Self::BlockStmt {
                resume,
                rest,
                tail,
                env,
                last,
            } => EvidenceContinuation::block_stmt(
                resume.clone(),
                rest.clone(),
                *tail,
                env.clone(),
                last.clone(),
                next,
            ),
            Self::RefSetReference { value, env } => {
                EvidenceContinuation::ref_set_reference(*value, env.clone(), next)
            }
            Self::RefSetForcedReference { value, env } => {
                EvidenceContinuation::ref_set_forced_reference(*value, env.clone(), next)
            }
            Self::RefSetValue { reference } => {
                EvidenceContinuation::ref_set_value(reference.clone(), next)
            }
            Self::RefSetForcedValue { reference } => {
                EvidenceContinuation::ref_set_forced_value(reference.clone(), next)
            }
            Self::RefSetResolvedUnit => EvidenceContinuation::ref_set_resolved_unit(next),
            Self::RefSetEmitResolvedRequest {
                request,
                assigned,
                mode,
            } => EvidenceContinuation::ref_set_emit_resolved_request(
                request.clone(),
                assigned.clone(),
                *mode,
                next,
            ),
            Self::ResolveRefSetValues {
                values,
                assigned,
                out,
                index,
                finish,
            } => EvidenceContinuation::resolve_ref_set_values(
                values.clone(),
                assigned.clone(),
                out.clone(),
                *index,
                finish.clone(),
                next,
            ),
            Self::ResolveRefSetFields {
                fields,
                assigned,
                out,
                index,
            } => EvidenceContinuation::resolve_ref_set_fields(
                fields.clone(),
                assigned.clone(),
                out.clone(),
                *index,
                next,
            ),
        }
    }
}

impl EvidenceEvalDeltaPlan {
    fn from_continuation(continuation: &EvidenceContinuation) -> Self {
        let mut frames = Vec::new();
        if let Some(frame) = continuation.frame() {
            frame.append_eval_delta_plan(&mut frames);
        }
        Self {
            frames: Rc::from(frames.into_boxed_slice()),
        }
    }

    fn frame_count(&self) -> usize {
        self.frames.len()
    }

    fn force_count(&self) -> usize {
        self.count_kind(EvidenceEvalDeltaFrameKind::Force)
    }

    fn apply_count(&self) -> usize {
        self.count_kind(EvidenceEvalDeltaFrameKind::Apply)
    }

    fn adapter_count(&self) -> usize {
        self.count_kind(EvidenceEvalDeltaFrameKind::Adapter)
    }

    fn case_count(&self) -> usize {
        self.count_kind(EvidenceEvalDeltaFrameKind::Case)
    }

    fn aggregate_count(&self) -> usize {
        self.count_kind(EvidenceEvalDeltaFrameKind::Aggregate)
    }

    fn select_count(&self) -> usize {
        self.count_kind(EvidenceEvalDeltaFrameKind::Select)
    }

    fn block_count(&self) -> usize {
        self.count_kind(EvidenceEvalDeltaFrameKind::Block)
    }

    fn ref_set_count(&self) -> usize {
        self.count_kind(EvidenceEvalDeltaFrameKind::RefSet)
    }

    fn count_kind(&self, kind: EvidenceEvalDeltaFrameKind) -> usize {
        self.frames
            .iter()
            .filter(|frame| frame.kind() == kind)
            .count()
    }
}

#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
struct EvidenceRequestDeltaId(usize);

#[derive(Debug, Clone, PartialEq)]
struct EvidenceRequestDeltaPlan {
    frames: Rc<[EvidenceRequestDeltaFramePlan]>,
}

#[derive(Debug, Clone, PartialEq)]
struct EvidenceRequestDeltaFramePlan {
    kind: EvidenceRequestDeltaFrameKind,
    catch_expr: ExprId,
    arms: Rc<[control_ir::CatchArm]>,
    env: Env,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum EvidenceRequestDeltaFrameKind {
    SameHandler,
    NoRoutedHandler,
    ForeignHandler,
}

#[derive(Debug, Clone, PartialEq)]
struct EvidenceCatchBoundaryDeltaPlan {
    mode: EvidenceCatchBoundaryMode,
    catch_expr: ExprId,
    arms: Rc<[control_ir::CatchArm]>,
    env: Env,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum EvidenceCatchBoundaryMode {
    SameHandler,
    ForeignPassThrough,
    NoRoutedHandler,
}

#[derive(Debug, Clone, Copy, Default, PartialEq, Eq)]
struct EvidenceCatchBoundaryShapeDigest {
    boundaries: usize,
    foreign_pass_through: usize,
    same_handler: usize,
    no_routed_handler: usize,
}

#[derive(Debug, Clone, Copy, Default, PartialEq, Eq)]
struct EvidenceCatchBoundaryMaterializedShapeDigest {
    catch_frames: usize,
    foreign_pass_through_frames: usize,
    same_handler_frames: usize,
    generic_fallback_frames: usize,
}

#[derive(Debug, Clone, Copy, Default, PartialEq, Eq)]
struct EvidenceCatchBoundaryDeltaShadowComparison {
    signal_shadow: usize,
    signal_match: usize,
    signal_mismatch: usize,
    generic_fallback_shadow: usize,
    generic_fallback_match: usize,
    generic_fallback_mismatch: usize,
    materialized_shape_shadow: usize,
    materialized_shape_match: usize,
    materialized_shape_mismatch: usize,
    value_resume_shadow: usize,
    value_resume_match: usize,
    value_resume_mismatch: usize,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum EvidenceCatchBoundarySignalClass {
    SameHandler,
    ForeignPassThrough,
    GenericFallback,
}

impl EvidenceCatchBoundaryDeltaPlan {
    fn foreign_pass_through(
        catch_expr: ExprId,
        arms: Rc<[control_ir::CatchArm]>,
        env: Env,
    ) -> Self {
        Self {
            mode: EvidenceCatchBoundaryMode::ForeignPassThrough,
            catch_expr,
            arms,
            env,
        }
    }

    fn from_request_delta_frame(frame: &EvidenceRequestDeltaFramePlan) -> Self {
        Self {
            mode: EvidenceCatchBoundaryMode::from_request_delta_kind(frame.kind),
            catch_expr: frame.catch_expr,
            arms: frame.arms.clone(),
            env: frame.env.clone(),
        }
    }

    fn is_signal_passthrough(&self) -> bool {
        matches!(self.mode, EvidenceCatchBoundaryMode::ForeignPassThrough)
    }

    fn has_value_resume_payload(&self) -> bool {
        true
    }

    fn signal_class(&self) -> EvidenceCatchBoundarySignalClass {
        EvidenceCatchBoundarySignalClass::from_boundary_mode(self.mode)
    }

    fn has_same_value_resume_payload_as(&self, frame: &EvidenceRequestDeltaFramePlan) -> bool {
        self.catch_expr == frame.catch_expr && self.arms == frame.arms && self.env == frame.env
    }
}

fn catch_boundaries_pass_direct_tail_signal(
    boundaries: &[EvidenceCatchBoundaryDeltaPlan],
    handler: ExprId,
) -> bool {
    boundaries
        .iter()
        .all(|boundary| boundary.catch_expr != handler)
}

fn catch_boundaries_are_foreign_pass_through(
    boundaries: &[EvidenceCatchBoundaryDeltaPlan],
) -> bool {
    !boundaries.is_empty()
        && boundaries
            .iter()
            .all(|boundary| boundary.is_signal_passthrough() && boundary.has_value_resume_payload())
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum EvidenceScopePlanDirectTailSignalReject {
    ScopeHasRequestBoundary,
    SameHandlerBoundary,
}

fn scope_plan_direct_tail_signal_compact_reject(
    scope_direct_tail_boundary_free: bool,
    boundaries: &[EvidenceCatchBoundaryDeltaPlan],
    handler: ExprId,
) -> Option<EvidenceScopePlanDirectTailSignalReject> {
    if !scope_direct_tail_boundary_free {
        return Some(EvidenceScopePlanDirectTailSignalReject::ScopeHasRequestBoundary);
    }
    if !catch_boundaries_pass_direct_tail_signal(boundaries, handler) {
        return Some(EvidenceScopePlanDirectTailSignalReject::SameHandlerBoundary);
    }
    None
}

impl EvidenceCatchBoundaryMode {
    fn from_request_delta_kind(kind: EvidenceRequestDeltaFrameKind) -> Self {
        match kind {
            EvidenceRequestDeltaFrameKind::SameHandler => Self::SameHandler,
            EvidenceRequestDeltaFrameKind::NoRoutedHandler => Self::NoRoutedHandler,
            EvidenceRequestDeltaFrameKind::ForeignHandler => Self::ForeignPassThrough,
        }
    }
}

impl EvidenceCatchBoundaryShapeDigest {
    fn from_deltas(deltas: &[EvidenceCatchBoundaryDeltaPlan]) -> Self {
        let mut digest = Self::default();
        for delta in deltas {
            digest.boundaries += 1;
            match delta.mode {
                EvidenceCatchBoundaryMode::SameHandler => digest.same_handler += 1,
                EvidenceCatchBoundaryMode::ForeignPassThrough => {
                    digest.foreign_pass_through += 1;
                }
                EvidenceCatchBoundaryMode::NoRoutedHandler => digest.no_routed_handler += 1,
            }
        }
        digest
    }

    fn is_foreign_pass_through_only(&self) -> bool {
        self.boundaries > 0
            && self.same_handler == 0
            && self.no_routed_handler == 0
            && self.foreign_pass_through == self.boundaries
    }
}

impl EvidenceCatchBoundaryMaterializedShapeDigest {
    fn from_deltas(deltas: &[EvidenceCatchBoundaryDeltaPlan]) -> Self {
        let mut digest = Self::default();
        for delta in deltas {
            digest.catch_frames += 1;
            match delta.mode {
                EvidenceCatchBoundaryMode::SameHandler => digest.same_handler_frames += 1,
                EvidenceCatchBoundaryMode::ForeignPassThrough => {
                    digest.foreign_pass_through_frames += 1;
                }
                EvidenceCatchBoundaryMode::NoRoutedHandler => {
                    digest.generic_fallback_frames += 1;
                }
            }
        }
        digest
    }

    fn from_request_delta_plan(plan: &EvidenceRequestDeltaPlan) -> Self {
        let mut digest = Self::default();
        for frame in plan.frames.iter() {
            digest.catch_frames += 1;
            match frame.kind {
                EvidenceRequestDeltaFrameKind::SameHandler => digest.same_handler_frames += 1,
                EvidenceRequestDeltaFrameKind::ForeignHandler => {
                    digest.foreign_pass_through_frames += 1;
                }
                EvidenceRequestDeltaFrameKind::NoRoutedHandler => {
                    digest.generic_fallback_frames += 1;
                }
            }
        }
        digest
    }
}

impl EvidenceCatchBoundarySignalClass {
    fn from_request_delta_kind(kind: EvidenceRequestDeltaFrameKind) -> Self {
        match kind {
            EvidenceRequestDeltaFrameKind::SameHandler => Self::SameHandler,
            EvidenceRequestDeltaFrameKind::ForeignHandler => Self::ForeignPassThrough,
            EvidenceRequestDeltaFrameKind::NoRoutedHandler => Self::GenericFallback,
        }
    }

    fn from_boundary_mode(mode: EvidenceCatchBoundaryMode) -> Self {
        match mode {
            EvidenceCatchBoundaryMode::SameHandler => Self::SameHandler,
            EvidenceCatchBoundaryMode::ForeignPassThrough => Self::ForeignPassThrough,
            EvidenceCatchBoundaryMode::NoRoutedHandler => Self::GenericFallback,
        }
    }

    fn is_generic_fallback(self) -> bool {
        matches!(self, Self::GenericFallback)
    }
}

impl EvidenceRequestDeltaPlan {
    fn from_continuation(
        continuation: &EvidenceContinuation,
        routed_yield_handler: Option<ExprId>,
    ) -> Self {
        let mut frames = Vec::new();
        if let Some(frame) = continuation.frame() {
            frame.append_request_delta_plan(&mut frames, routed_yield_handler);
        }
        Self {
            frames: Rc::from(frames.into_boxed_slice()),
        }
    }

    fn frame_count(&self) -> usize {
        self.frames.len()
    }

    fn foreign_handler_count(&self) -> usize {
        self.frames
            .iter()
            .filter(|frame| matches!(frame.kind, EvidenceRequestDeltaFrameKind::ForeignHandler))
            .count()
    }

    fn same_handler_count(&self) -> usize {
        self.frames
            .iter()
            .filter(|frame| matches!(frame.kind, EvidenceRequestDeltaFrameKind::SameHandler))
            .count()
    }

    fn no_routed_handler_count(&self) -> usize {
        self.frames
            .iter()
            .filter(|frame| matches!(frame.kind, EvidenceRequestDeltaFrameKind::NoRoutedHandler))
            .count()
    }

    fn is_foreign_pass_through_only(&self) -> bool {
        self.frame_count() > 0
            && self.same_handler_count() == 0
            && self.no_routed_handler_count() == 0
            && self.foreign_handler_count() == self.frame_count()
    }

    fn catch_boundary_delta_plans(&self) -> Vec<EvidenceCatchBoundaryDeltaPlan> {
        self.frames
            .iter()
            .map(EvidenceCatchBoundaryDeltaPlan::from_request_delta_frame)
            .collect()
    }

    fn catch_boundary_shape_digest(&self) -> EvidenceCatchBoundaryShapeDigest {
        let mut digest = EvidenceCatchBoundaryShapeDigest::default();
        for frame in self.frames.iter() {
            digest.boundaries += 1;
            match EvidenceCatchBoundaryMode::from_request_delta_kind(frame.kind) {
                EvidenceCatchBoundaryMode::SameHandler => digest.same_handler += 1,
                EvidenceCatchBoundaryMode::ForeignPassThrough => {
                    digest.foreign_pass_through += 1;
                }
                EvidenceCatchBoundaryMode::NoRoutedHandler => digest.no_routed_handler += 1,
            }
        }
        digest
    }

    fn catch_boundary_delta_shadow_comparison(
        &self,
        deltas: &[EvidenceCatchBoundaryDeltaPlan],
    ) -> EvidenceCatchBoundaryDeltaShadowComparison {
        let mut comparison = EvidenceCatchBoundaryDeltaShadowComparison::default();
        for (frame, delta) in self.frames.iter().zip(deltas.iter()) {
            comparison.signal_shadow += 1;
            let legacy_signal =
                EvidenceCatchBoundarySignalClass::from_request_delta_kind(frame.kind);
            if delta.signal_class() == legacy_signal {
                comparison.signal_match += 1;
            } else {
                comparison.signal_mismatch += 1;
            }

            comparison.generic_fallback_shadow += 1;
            let legacy_generic_fallback = legacy_signal.is_generic_fallback();
            let delta_generic_fallback = delta.signal_class().is_generic_fallback();
            if delta_generic_fallback == legacy_generic_fallback {
                comparison.generic_fallback_match += 1;
            } else {
                comparison.generic_fallback_mismatch += 1;
            }

            comparison.value_resume_shadow += 1;
            if delta.has_same_value_resume_payload_as(frame) {
                comparison.value_resume_match += 1;
            } else {
                comparison.value_resume_mismatch += 1;
            }
        }

        comparison.materialized_shape_shadow += 1;
        if EvidenceCatchBoundaryMaterializedShapeDigest::from_deltas(deltas)
            == EvidenceCatchBoundaryMaterializedShapeDigest::from_request_delta_plan(self)
        {
            comparison.materialized_shape_match += 1;
        } else {
            comparison.materialized_shape_mismatch += 1;
        }

        comparison
    }
}

