#[derive(Debug, Clone, PartialEq, Eq, Default)]
struct EvidenceSignalHygiene {
    guard_ids: Vec<EvidenceGuardId>,
    carried_guards: Vec<EvidenceCarriedGuard>,
    handler_boundary: Option<EvidenceHandlerBoundary>,
    permission_visibility: EvidenceSignalPermissionVisibility,
    #[cfg(debug_assertions)]
    provider_add_id_shortcut_full_scan: Option<Box<EvidenceFullScanHygieneSnapshot>>,
    #[cfg(debug_assertions)]
    resume_marker_provider_pair_close_shadow: Option<EvidenceResumeMarkerCloseShadow>,
    #[cfg(debug_assertions)]
    resume_marker_provider_prefix_boundary_close_shadow:
        Option<EvidenceProviderPrefixBoundaryCloseCert>,
    #[cfg(debug_assertions)]
    provider_env_foreign_boundary_shadow: Option<EvidenceProviderEnvForeignBoundaryGrantCert>,
    #[cfg(debug_assertions)]
    provider_env_foreign_miss_boundary_shadow: Option<EvidenceProviderEnvForeignBoundaryMissCert>,
    #[cfg(debug_assertions)]
    provider_env_foreign_later_grant_shadow: Option<EvidenceProviderEnvLaterGrantShadow>,
}

impl EvidenceSignalHygiene {
    fn new() -> Self {
        Self::default()
    }

    fn from_request(request: &mut EvidenceRequest) -> Self {
        mem::take(&mut request.hygiene)
    }

    fn apply_to_request(self, request: &mut EvidenceRequest) {
        request.hygiene = self;
    }

    fn push_guard_id(&mut self, id: EvidenceGuardId) -> bool {
        let pushed = push_unique_guard(&mut self.guard_ids, id);
        if pushed {
            self.permission_visibility.record_guard_mask();
        }
        pushed
    }

    fn set_handler_boundary(&mut self, handler_boundary: EvidenceHandlerBoundary) {
        self.permission_visibility.record_handler_boundary_mask();
        self.handler_boundary = Some(handler_boundary);
        #[cfg(debug_assertions)]
        if let Some(full_scan) = self.provider_add_id_shortcut_full_scan.as_mut() {
            full_scan.handler_boundary = self.handler_boundary.clone();
        }
    }

    fn with_operation_visibility(
        mut self,
        visibility: Option<RuntimeEvidenceOperationVisibility>,
    ) -> Self {
        self.permission_visibility.set_base(visibility);
        self
    }

    fn push_carried_guard(&mut self, guard: EvidenceCarriedGuard) {
        self.permission_visibility.record_resume_delta();
        self.carried_guards.push(guard);
    }

    fn permission_shadow_kind(&self) -> Option<EvidencePermissionShadowKind> {
        self.permission_visibility.shadow_kind()
    }

    fn provider_grant_permission(&self) -> Option<RuntimeEvidenceProviderGrantPermission> {
        self.permission_visibility.base?.provider_grant_permission()
    }

    fn permission_transform(&self) -> EvidenceSignalPermissionTransform {
        self.permission_visibility.transform
    }

    fn legacy_guard_bridge(&self) -> bool {
        self.permission_visibility
            .base
            .is_some_and(|visibility| visibility.legacy_guard_bridge())
    }

    #[cfg(debug_assertions)]
    fn set_provider_add_id_shortcut_full_scan(
        &mut self,
        full_scan: EvidenceFullScanHygieneSnapshot,
    ) {
        self.provider_add_id_shortcut_full_scan = Some(Box::new(full_scan));
    }

    #[cfg(debug_assertions)]
    fn provider_add_id_shortcut_full_scan(&self) -> Option<&EvidenceFullScanHygieneSnapshot> {
        self.provider_add_id_shortcut_full_scan.as_deref()
    }

    #[cfg(debug_assertions)]
    fn set_resume_marker_provider_pair_close_shadow(
        &mut self,
        shadow: EvidenceResumeMarkerCloseShadow,
    ) {
        self.resume_marker_provider_pair_close_shadow = Some(shadow);
    }

    #[cfg(debug_assertions)]
    fn resume_marker_provider_pair_close_shadow(&self) -> Option<EvidenceResumeMarkerCloseShadow> {
        self.resume_marker_provider_pair_close_shadow
    }

    #[cfg(debug_assertions)]
    fn set_resume_marker_provider_prefix_boundary_close_shadow(
        &mut self,
        cert: EvidenceProviderPrefixBoundaryCloseCert,
    ) {
        self.resume_marker_provider_prefix_boundary_close_shadow = Some(cert);
    }

    #[cfg(debug_assertions)]
    fn resume_marker_provider_prefix_boundary_close_shadow(
        &self,
    ) -> Option<EvidenceProviderPrefixBoundaryCloseCert> {
        self.resume_marker_provider_prefix_boundary_close_shadow
    }

    #[cfg(debug_assertions)]
    fn set_provider_env_foreign_boundary_shadow(
        &mut self,
        cert: EvidenceProviderEnvForeignBoundaryGrantCert,
    ) {
        self.provider_env_foreign_boundary_shadow = Some(cert);
    }

    #[cfg(debug_assertions)]
    fn provider_env_foreign_boundary_shadow(
        &self,
    ) -> Option<EvidenceProviderEnvForeignBoundaryGrantCert> {
        self.provider_env_foreign_boundary_shadow
    }

    #[cfg(debug_assertions)]
    fn set_provider_env_foreign_miss_boundary_shadow(
        &mut self,
        cert: EvidenceProviderEnvForeignBoundaryMissCert,
    ) {
        self.provider_env_foreign_miss_boundary_shadow = Some(cert);
    }

    #[cfg(debug_assertions)]
    fn provider_env_foreign_miss_boundary_shadow(
        &self,
    ) -> Option<EvidenceProviderEnvForeignBoundaryMissCert> {
        self.provider_env_foreign_miss_boundary_shadow
    }

    #[cfg(debug_assertions)]
    fn set_provider_env_foreign_later_grant_shadow(
        &mut self,
        shadow: EvidenceProviderEnvLaterGrantShadow,
    ) {
        self.provider_env_foreign_later_grant_shadow = Some(shadow);
    }

    #[cfg(debug_assertions)]
    fn provider_env_foreign_later_grant_shadow(
        &self,
    ) -> Option<EvidenceProviderEnvLaterGrantShadow> {
        self.provider_env_foreign_later_grant_shadow
    }

    #[cfg(debug_assertions)]
    fn operation_visibility(&self) -> Option<RuntimeEvidenceOperationVisibility> {
        self.permission_visibility.base
    }
}

