    fn is_identity(&self) -> bool {
        matches!(self, Self::Identity)
    }

    fn then_counted(
        self,
        tail: Self,
        stats: &mut RuntimeEvidenceRunStats,
        source: EvidenceContinuationAppendSource,
    ) -> Self {
        if tail.is_identity() {
            return self;
        }
        if self.is_identity() {
            return tail;
        }
        let mut head = self;
        match head.try_append_owned_tail_counted(tail, stats, source) {
            Ok(()) => {
                stats.continuation_owned_tail_appends += 1;
                record_continuation_append_owned_tail(stats, source);
                return head;
            }
            Err(tail) => {
                stats.continuation_append_steps += 1;
                record_continuation_append_then(stats, source);
                return Self::Frame(Rc::new(EvidenceContinuationFrame::Then {
                    first: head,
                    second: tail,
                }));
            }
        }
    }

    fn try_append_owned_tail_counted(
        &mut self,
        tail: Self,
        stats: &mut RuntimeEvidenceRunStats,
        source: EvidenceContinuationAppendSource,
    ) -> Result<(), Self> {
        if tail.is_identity() {
            return Ok(());
        }
        match self {
            Self::Identity => {
                *self = tail;
                Ok(())
            }
            Self::Frame(frame) => {
                if let Some(frame) = Rc::get_mut(frame) {
                    return frame.try_append_owned_tail_counted(tail, stats, source);
                }

                // A shared frame does not imply a dynamic scope boundary. Clone the pure
                // continuation spine and append into the clone when the existing tail rules allow
                // it, so repeated resumes do not pay an extra Then frame solely for Rc sharing.
                let mut cloned = frame.as_ref().clone();
                match cloned.try_append_owned_tail_counted(tail, stats, source) {
                    Ok(()) => {
                        *self = Self::Frame(Rc::new(cloned));
                        Ok(())
                    }
                    Err(tail) => {
                        record_continuation_append_blocker(
                            stats,
                            source,
                            EvidenceContinuationAppendBlocker::RcShared,
                        );
                        Err(tail)
                    }
                }
            }
        }
    }

