fn runtime_expr_cache(program: &Program) -> Vec<RuntimeEvidenceExpr> {
    program
        .exprs
        .iter()
        .enumerate()
        .map(|(index, expr)| match expr {
            Expr::Lit(lit) => RuntimeEvidenceExpr::Value(shared(value_from_lit(lit))),
            Expr::Constructor { def, arity } => {
                RuntimeEvidenceExpr::Value(shared(constructor_value(*def, *arity, Vec::new())))
            }
            Expr::EffectOp { path, .. } => {
                RuntimeEvidenceExpr::Value(shared(RuntimeEvidenceValue::EffectOp {
                    expr: ExprId(index as u32),
                    path: shared_path(path),
                }))
            }
            Expr::PrimitiveOp { op, context } if op.arity() > 0 => {
                RuntimeEvidenceExpr::Value(shared(RuntimeEvidenceValue::PrimitiveOp {
                    op: *op,
                    context: context.clone(),
                    args: PrimitiveArgs::new(),
                }))
            }
            Expr::PrimitiveOp { op, context } => RuntimeEvidenceExpr::NullaryPrimitive {
                op: *op,
                context: context.clone(),
            },
            Expr::Local(def) => RuntimeEvidenceExpr::Local {
                slot: EnvSlot::from(*def),
                def: *def,
            },
            Expr::InstanceRef(instance) => RuntimeEvidenceExpr::Instance(*instance),
            Expr::Coerce { expr, .. } => RuntimeEvidenceExpr::Alias(*expr),
            Expr::MakeThunk { target, body, .. } => RuntimeEvidenceExpr::MakeThunk {
                body: *body,
                provider_expr: ExprId(index as u32),
                needs_hygiene_mark: effective_thunk_type_may_need_hygiene_mark(target),
            },
            Expr::Lambda { param, body } => RuntimeEvidenceExpr::Lambda {
                param: shared_pat(param),
                body: *body,
                provider_expr: ExprId(index as u32),
            },
            Expr::FunctionAdapter {
                source,
                target,
                function,
                hygiene,
            } => RuntimeEvidenceExpr::FunctionAdapter {
                source: source.clone(),
                target: target.clone(),
                function: *function,
                hygiene: hygiene.clone(),
                provider_expr: ExprId(index as u32),
            },
            Expr::ForceThunk { target, thunk, .. } => {
                let target_value_is_thunk = matches!(target.value, Type::Thunk { .. });
                if let Some((site, effect, path, arg)) = forced_effect_call_parts(program, *thunk) {
                    RuntimeEvidenceExpr::ForceEffectCall {
                        target_value_is_thunk,
                        site,
                        effect,
                        path: shared_path(path),
                        arg,
                    }
                } else {
                    RuntimeEvidenceExpr::ForceThunk {
                        target_value_is_thunk,
                        thunk: *thunk,
                    }
                }
            }
            Expr::MarkerFrame { path, body } => RuntimeEvidenceExpr::MarkerFrame {
                path: Rc::from(path.clone().into_boxed_slice()),
                body: *body,
            },
            Expr::Apply { callee, arg } => RuntimeEvidenceExpr::Apply {
                site: ExprId(index as u32),
                callee: *callee,
                arg: *arg,
            },
            Expr::RefSet { reference, value } => RuntimeEvidenceExpr::RefSet {
                reference: *reference,
                value: *value,
            },
            Expr::Tuple(items) => RuntimeEvidenceExpr::Tuple(shared_expr_ids(items)),
            Expr::Record { fields, spread } => RuntimeEvidenceExpr::Record {
                fields: shared_record_fields(fields),
                spread: spread.clone(),
            },
            Expr::PolyVariant { tag, payloads } => RuntimeEvidenceExpr::PolyVariant {
                tag: tag.clone(),
                payloads: shared_expr_ids(payloads),
            },
            Expr::Select {
                base,
                name,
                resolution,
            } => RuntimeEvidenceExpr::Select {
                base: *base,
                name: name.clone(),
                resolution: resolution.clone(),
            },
            Expr::Case { scrutinee, .. } => RuntimeEvidenceExpr::Case {
                expr: ExprId(index as u32),
                scrutinee: *scrutinee,
            },
            Expr::Catch { body, .. } => RuntimeEvidenceExpr::Catch {
                expr: ExprId(index as u32),
                body: *body,
            },
            Expr::Block(block) => RuntimeEvidenceExpr::Block {
                stmts: shared_stmts(&block.stmts),
                tail: block.tail,
            },
        })
        .collect()
}

fn forced_effect_call_parts(
    program: &Program,
    thunk: ExprId,
) -> Option<(ExprId, ExprId, &[String], ExprId)> {
    let site = thunk;
    let Expr::Apply { callee, arg } = program.exprs.get(thunk.0 as usize)? else {
        return None;
    };
    let Expr::EffectOp { path, .. } = program.exprs.get(callee.0 as usize)? else {
        return None;
    };
    Some((site, *callee, path, *arg))
}

fn static_arm_caches(
    program: &Program,
) -> (
    Vec<Option<Rc<[control_ir::CaseArm]>>>,
    Vec<Option<Rc<[control_ir::CatchArm]>>>,
) {
    let mut case_arms = Vec::with_capacity(program.exprs.len());
    let mut catch_arms = Vec::with_capacity(program.exprs.len());
    for expr in &program.exprs {
        match expr {
            Expr::Case { arms, .. } => {
                case_arms.push(Some(shared_case_arms(arms)));
                catch_arms.push(None);
            }
            Expr::Catch { arms, .. } => {
                case_arms.push(None);
                catch_arms.push(Some(shared_catch_arms(arms)));
            }
            _ => {
                case_arms.push(None);
                catch_arms.push(None);
            }
        }
    }
    (case_arms, catch_arms)
}

fn env_preserving_expr_cache(runtime_exprs: &[RuntimeEvidenceExpr]) -> Vec<bool> {
    // This proof is only about the caller Env not being extended. It is not an
    // effect-freedom proof; effectful work may still happen behind an internal
    // env clone or a captured continuation.
    let mut preserving = vec![false; runtime_exprs.len()];
    let mut changed = true;
    while changed {
        changed = false;
        for (index, expr) in runtime_exprs.iter().enumerate() {
            if preserving[index] || !runtime_expr_preserves_env(expr, &preserving) {
                continue;
            }
            preserving[index] = true;
            changed = true;
        }
    }
    preserving
}

fn runtime_expr_preserves_env(expr: &RuntimeEvidenceExpr, preserving: &[bool]) -> bool {
    match expr {
        RuntimeEvidenceExpr::Value(_)
        | RuntimeEvidenceExpr::NullaryPrimitive { .. }
        | RuntimeEvidenceExpr::Local { .. }
        | RuntimeEvidenceExpr::Instance(_)
        | RuntimeEvidenceExpr::MakeThunk { .. }
        | RuntimeEvidenceExpr::Lambda { .. }
        | RuntimeEvidenceExpr::ForceEffectCall { .. }
        | RuntimeEvidenceExpr::RefSet { .. }
        | RuntimeEvidenceExpr::Catch { .. } => true,
        RuntimeEvidenceExpr::Alias(expr)
        | RuntimeEvidenceExpr::FunctionAdapter { function: expr, .. }
        | RuntimeEvidenceExpr::ForceThunk { thunk: expr, .. }
        | RuntimeEvidenceExpr::MarkerFrame { body: expr, .. }
        | RuntimeEvidenceExpr::Select { base: expr, .. }
        | RuntimeEvidenceExpr::Case {
            scrutinee: expr, ..
        } => expr_id_preserves_env(*expr, preserving),
        RuntimeEvidenceExpr::Apply { callee, .. } => {
            // Non-immediate args are evaluated in an internal cloned env.
            expr_id_preserves_env(*callee, preserving)
        }
        RuntimeEvidenceExpr::Tuple(items)
        | RuntimeEvidenceExpr::PolyVariant {
            payloads: items, ..
        } => expr_ids_preserve_env(items, preserving),
        RuntimeEvidenceExpr::Record { fields, spread } => {
            record_spread_preserves_env(spread, preserving)
                && fields
                    .iter()
                    .all(|field| expr_id_preserves_env(field.value, preserving))
        }
        RuntimeEvidenceExpr::Block { stmts, tail } => {
            stmts
                .iter()
                .all(|stmt| stmt_preserves_env(stmt, preserving))
                && tail.map_or(true, |tail| expr_id_preserves_env(tail, preserving))
        }
    }
}

fn expr_ids_preserve_env(exprs: &[ExprId], preserving: &[bool]) -> bool {
    exprs
        .iter()
        .all(|expr| expr_id_preserves_env(*expr, preserving))
}

fn expr_id_preserves_env(expr: ExprId, preserving: &[bool]) -> bool {
    preserving.get(expr.0 as usize).copied().unwrap_or(false)
}

fn record_spread_preserves_env(spread: &RecordSpread<ExprId>, preserving: &[bool]) -> bool {
    match spread {
        RecordSpread::None => true,
        RecordSpread::Head(expr) | RecordSpread::Tail(expr) => {
            expr_id_preserves_env(*expr, preserving)
        }
    }
}

fn stmt_preserves_env(stmt: &Stmt, preserving: &[bool]) -> bool {
    match stmt {
        Stmt::Expr(expr) => expr_id_preserves_env(*expr, preserving),
        Stmt::Let(..) | Stmt::Module(..) => false,
    }
}

