    #[test]
    fn resume_plan_shadow_profile_splits_boundary_scope_and_provider_lanes() {
        let catch_expr = ExprId(12);
        let markers: Rc<[EvidenceValueMarker]> =
            vec![EvidenceValueMarker::AddId(Rc::new(EvidenceAddIdMarker {
                id: EvidenceGuardId(1),
                path: shared_path(&permission_test_path()),
                depth: 0,
                guard_own_path: true,
                guard_foreign_path: false,
                carry_after_frame: false,
                preserve_own_on_resume: false,
            }))]
            .into();
        let continuation = EvidenceContinuation::catch_body(
            catch_expr,
            empty_catch_arms(),
            Env::new(),
            EvidenceContinuation::marker_frame(
                markers,
                true,
                None,
                EvidenceContinuation::provider_env(
                    provider_env_fixture_for_handler(7),
                    EvidenceContinuation::identity(),
                ),
            ),
        );

        let profile = continuation.resume_plan_shadow_profile(Some(catch_expr));

        assert_eq!(profile.catch_boundaries, 1);
        assert_eq!(profile.eval_frames, 0);
        assert_eq!(profile.catch_same_handler, 1);
        assert_eq!(profile.marker_frames, 1);
        assert_eq!(profile.marker_dynamic_frames, 1);
        assert_eq!(profile.marker_active_add_id_ops, 1);
        assert_eq!(profile.provider_env_deltas, 1);
        assert!(profile.has_catch_boundary());
        assert!(profile.has_dynamic_marker());
        assert!(profile.has_provider_delta());
        assert!(!profile.is_eval_only());
        assert_eq!(profile.request_delta_rejection(), None);

        let marker_delta = continuation.marker_delta_shadow_key();
        assert_eq!(marker_delta.frame_count(), 1);
        assert_eq!(marker_delta.active_add_id_ops(), 1);
        assert_eq!(marker_delta.handler_boundary_ops(), 0);

        let provider_delta = continuation.provider_delta_shadow_key();
        assert_eq!(provider_delta.frame_count(), 1);
        assert_eq!(provider_delta.slot_count(), 1);
        assert_eq!(provider_delta.handler_candidate_count(), 1);

        let eval_delta = EvidenceEvalDeltaPlan::from_continuation(&continuation);
        assert_eq!(eval_delta.frame_count(), 0);
        assert_eq!(eval_delta.force_count(), 0);
        assert_eq!(eval_delta.apply_count(), 0);

        let trace = EvidenceResumePlanTracePlan::from_continuation(&continuation, Some(catch_expr));
        assert_eq!(trace.step_count(), 3);
        assert_eq!(trace.request_count(), 1);
        assert_eq!(trace.marker_count(), 1);
        assert_eq!(trace.provider_count(), 1);
        assert_eq!(
            trace.steps.as_ref(),
            &[
                EvidenceResumePlanStep::Request(0),
                EvidenceResumePlanStep::Marker(0),
                EvidenceResumePlanStep::Provider(0),
            ]
        );

        let request_delta =
            EvidenceRequestDeltaPlan::from_continuation(&continuation, Some(catch_expr));
        assert_eq!(request_delta.frame_count(), 1);
        assert_eq!(request_delta.same_handler_count(), 1);
        assert_eq!(request_delta.no_routed_handler_count(), 0);
        assert_eq!(request_delta.foreign_handler_count(), 0);
        assert_eq!(
            request_delta.frames[0].kind,
            EvidenceRequestDeltaFrameKind::SameHandler
        );
        assert_eq!(request_delta.frames[0].catch_expr, catch_expr);
    }

