    #[test]
    fn request_delta_identifies_foreign_pass_through_boundaries() {
        let outer = ExprId(12);
        let routed = ExprId(13);
        let continuation = EvidenceContinuation::catch_body(
            outer,
            empty_catch_arms(),
            Env::new(),
            EvidenceContinuation::catch_body(
                ExprId(14),
                empty_catch_arms(),
                Env::new(),
                EvidenceContinuation::identity(),
            ),
        );

        let foreign_delta =
            EvidenceRequestDeltaPlan::from_continuation(&continuation, Some(routed));
        assert_eq!(foreign_delta.frame_count(), 2);
        assert_eq!(foreign_delta.foreign_handler_count(), 2);
        assert!(foreign_delta.is_foreign_pass_through_only());
        assert_eq!(
            foreign_delta.catch_boundary_shape_digest(),
            EvidenceCatchBoundaryShapeDigest {
                boundaries: 2,
                foreign_pass_through: 2,
                same_handler: 0,
                no_routed_handler: 0,
            }
        );
        let foreign_boundary_deltas = foreign_delta.catch_boundary_delta_plans();
        assert_eq!(foreign_boundary_deltas.len(), 2);
        assert!(
            foreign_boundary_deltas
                .iter()
                .all(EvidenceCatchBoundaryDeltaPlan::is_signal_passthrough)
        );
        assert!(
            foreign_boundary_deltas
                .iter()
                .all(EvidenceCatchBoundaryDeltaPlan::has_value_resume_payload)
        );
        assert_eq!(
            foreign_delta.catch_boundary_delta_shadow_comparison(&foreign_boundary_deltas),
            EvidenceCatchBoundaryDeltaShadowComparison {
                signal_shadow: 2,
                signal_match: 2,
                signal_mismatch: 0,
                generic_fallback_shadow: 2,
                generic_fallback_match: 2,
                generic_fallback_mismatch: 0,
                materialized_shape_shadow: 1,
                materialized_shape_match: 1,
                materialized_shape_mismatch: 0,
                value_resume_shadow: 2,
                value_resume_match: 2,
                value_resume_mismatch: 0,
            }
        );

        let same_delta = EvidenceRequestDeltaPlan::from_continuation(&continuation, Some(outer));
        assert_eq!(same_delta.same_handler_count(), 1);
        assert!(!same_delta.is_foreign_pass_through_only());
        assert_eq!(
            same_delta.catch_boundary_shape_digest(),
            EvidenceCatchBoundaryShapeDigest {
                boundaries: 2,
                foreign_pass_through: 1,
                same_handler: 1,
                no_routed_handler: 0,
            }
        );
        let same_boundary_deltas = same_delta.catch_boundary_delta_plans();
        assert_eq!(
            same_delta.catch_boundary_delta_shadow_comparison(&same_boundary_deltas),
            EvidenceCatchBoundaryDeltaShadowComparison {
                signal_shadow: 2,
                signal_match: 2,
                signal_mismatch: 0,
                generic_fallback_shadow: 2,
                generic_fallback_match: 2,
                generic_fallback_mismatch: 0,
                materialized_shape_shadow: 1,
                materialized_shape_match: 1,
                materialized_shape_mismatch: 0,
                value_resume_shadow: 2,
                value_resume_match: 2,
                value_resume_mismatch: 0,
            }
        );

        let no_routed_delta = EvidenceRequestDeltaPlan::from_continuation(&continuation, None);
        assert_eq!(no_routed_delta.no_routed_handler_count(), 2);
        assert!(!no_routed_delta.is_foreign_pass_through_only());
        assert_eq!(
            no_routed_delta.catch_boundary_shape_digest(),
            EvidenceCatchBoundaryShapeDigest {
                boundaries: 2,
                foreign_pass_through: 0,
                same_handler: 0,
                no_routed_handler: 2,
            }
        );
        let no_routed_boundary_deltas = no_routed_delta.catch_boundary_delta_plans();
        assert_eq!(
            no_routed_delta.catch_boundary_delta_shadow_comparison(&no_routed_boundary_deltas),
            EvidenceCatchBoundaryDeltaShadowComparison {
                signal_shadow: 2,
                signal_match: 2,
                signal_mismatch: 0,
                generic_fallback_shadow: 2,
                generic_fallback_match: 2,
                generic_fallback_mismatch: 0,
                materialized_shape_shadow: 1,
                materialized_shape_match: 1,
                materialized_shape_mismatch: 0,
                value_resume_shadow: 2,
                value_resume_match: 2,
                value_resume_mismatch: 0,
            }
        );
    }

